import assert from 'node:assert';
import { after, before, test } from 'node:test';
import type { FastifyInstance } from 'fastify';
import { buildTestApp, createAndLogin } from './support/app.js';

let ctx: Awaited<ReturnType<typeof buildTestApp>>;
let app: FastifyInstance;
let cookie: string;
let bobCookie: string;
let aliceId: string;
let bobId: string;

const j = (method: string, url: string, payload?: object, c: string = cookie) =>
  app.inject({
    method: method as 'GET',
    url,
    headers: { cookie: c },
    ...(payload ? { payload } : {}),
  });

async function bootstrap(c: string = cookie) {
  return (
    await app.inject({ method: 'GET', url: '/api/bootstrap', headers: { cookie: c } })
  ).json();
}

// a read-only PAT (tasks:read) for the current cookie's user
async function readOnlyToken(c: string = cookie): Promise<string> {
  return (await j('POST', '/api/auth/tokens', { name: 'ro', scopes: ['tasks:read'] }, c)).json()
    .token;
}

before(async () => {
  ctx = await buildTestApp();
  app = ctx.app;
  const alice = await createAndLogin(app, ctx.db);
  cookie = alice.cookie;
  aliceId = alice.user.id;
  const bob = await createAndLogin(
    app,
    ctx.db,
    { username: 'bob', email: 'bob@example.com', password: 'Sup3r!secret' },
    { isAdmin: false },
  );
  bobCookie = bob.cookie;
  bobId = bob.user.id;
});
after(async () => {
  await app.close();
});

// ---- POST /api/tasks/:id/assign --------------------------------------------

test('assign a task to a valid user returns the updated task', async () => {
  const task = (await j('POST', '/api/tasks', { title: 'assignable' })).json();
  const res = await j('POST', `/api/tasks/${task.id}/assign`, { assigneeId: bobId });
  assert.equal(res.statusCode, 200);
  assert.equal(res.json().id, task.id);
  assert.equal(res.json().assigneeId, bobId);
});

// QUIRK: the AssignSchema accepts `null`, but ajv type-coercion on the
// string|null union turns a JSON `null` into '' before the handler runs, so
// clearing an assignee through the route reaches assignTask with '' (no such
// user id) and trips the assignee_id FK → 500. Documented, not asserted as
// desired. (Clearing at the service level is covered in tasks-extra.test.ts.)
test('assign with a null assigneeId is coerced to "" and currently errors', async () => {
  const task = (await j('POST', '/api/tasks', { title: 'clear me', assigneeId: bobId })).json();
  assert.equal(task.assigneeId, bobId);
  const res = await j('POST', `/api/tasks/${task.id}/assign`, { assigneeId: null });
  assert.equal(res.statusCode, 500);
});

test('assign to a nonexistent user returns 400 badAssignee', async () => {
  const task = (await j('POST', '/api/tasks', { title: 'bad assignee' })).json();
  const res = await j('POST', `/api/tasks/${task.id}/assign`, { assigneeId: 'no-such-user' });
  assert.equal(res.statusCode, 400);
  assert.equal(res.json().error, 'assignee does not exist');
  assert.equal(res.json().field, 'assigneeId');
});

test('assign on a missing task returns 404', async () => {
  const res = await j('POST', '/api/tasks/ghost-task/assign', { assigneeId: aliceId });
  assert.equal(res.statusCode, 404);
  assert.equal(res.json().error, 'not found');
});

test('assign without write scope (read-only PAT) returns 403', async () => {
  const task = (await j('POST', '/api/tasks', { title: 'ro assign' })).json();
  const tok = await readOnlyToken();
  const res = await app.inject({
    method: 'POST',
    url: `/api/tasks/${task.id}/assign`,
    headers: { authorization: `Bearer ${tok}` },
    payload: { assigneeId: bobId },
  });
  assert.equal(res.statusCode, 403);
});

test("assign another user's task returns 404", async () => {
  const task = (await j('POST', '/api/tasks', { title: 'alice private' })).json();
  const res = await j('POST', `/api/tasks/${task.id}/assign`, { assigneeId: bobId }, bobCookie);
  assert.equal(res.statusCode, 404);
});

// ---- POST /api/tasks/:id/complete ------------------------------------------

test('complete a non-recurring task marks it done with no created occurrences', async () => {
  const task = (await j('POST', '/api/tasks', { title: 'one-off' })).json();
  assert.equal(task.done, false);
  const res = await j('POST', `/api/tasks/${task.id}/complete`);
  assert.equal(res.statusCode, 200);
  const body = res.json();
  assert.equal(body.task.id, task.id);
  assert.equal(body.task.done, true);
  assert.ok(body.task.completedAt);
  assert.deepEqual(body.created, []);
});

test('complete a recurring task spawns the next occurrence', async () => {
  const task = (
    await j('POST', '/api/tasks', {
      title: 'daily standup',
      recurrence: 'daily',
      due: '2026-06-25',
    })
  ).json();
  const res = await j('POST', `/api/tasks/${task.id}/complete`);
  assert.equal(res.statusCode, 200);
  const body = res.json();
  // completed original
  assert.equal(body.task.id, task.id);
  assert.equal(body.task.done, true);
  assert.ok(body.task.completedAt);
  // one fresh, unchecked occurrence with the next due date
  assert.equal(body.created.length, 1);
  const next = body.created[0];
  assert.notEqual(next.id, task.id);
  assert.equal(next.done, false);
  assert.equal(next.completedAt, null);
  assert.equal(next.recurrence, 'daily');
  assert.equal(next.title, 'daily standup');
  assert.notEqual(next.due, task.due);
  // the new occurrence is live in bootstrap; the completed one is too
  const boot = await bootstrap();
  const ids = new Set(boot.tasks.map((t: { id: string }) => t.id));
  assert.ok(ids.has(next.id));
});

test('complete a recurring task also clones its subtask subtree (unchecked)', async () => {
  const root = (
    await j('POST', '/api/tasks', {
      title: 'weekly review',
      recurrence: 'daily',
      due: '2026-06-25',
    })
  ).json();
  await j('POST', '/api/tasks', { title: 'sub', parentId: root.id });

  const res = await j('POST', `/api/tasks/${root.id}/complete`);
  assert.equal(res.statusCode, 200);
  const body = res.json();
  // a fresh root clone plus a fresh subtask clone
  assert.equal(body.created.length, 2);
  for (const c of body.created) {
    assert.equal(c.done, false);
    assert.equal(c.completedAt, null);
  }
});

test('complete a missing task returns 404', async () => {
  const res = await j('POST', '/api/tasks/ghost-complete/complete');
  assert.equal(res.statusCode, 404);
  assert.equal(res.json().error, 'not found');
});

test('complete without write scope (read-only PAT) returns 403', async () => {
  const task = (await j('POST', '/api/tasks', { title: 'ro complete' })).json();
  const tok = await readOnlyToken();
  const res = await app.inject({
    method: 'POST',
    url: `/api/tasks/${task.id}/complete`,
    headers: { authorization: `Bearer ${tok}` },
  });
  assert.equal(res.statusCode, 403);
});

test("complete another user's task returns 404", async () => {
  const task = (await j('POST', '/api/tasks', { title: 'alice-only complete' })).json();
  const res = await j('POST', `/api/tasks/${task.id}/complete`, undefined, bobCookie);
  assert.equal(res.statusCode, 404);
});

// Test helper: build an app on a fresh in-memory DB, and create+login a user,
// replaying the login-issued SIGNED cookie (never hand-signing).

process.env.SESSION_SECRET ||= 'test-secret-please-change';

import type { FastifyInstance } from 'fastify';
import { buildApp } from '../../src/app.js';
import { type DB, type Sqlite, openDatabase } from '../../src/db.js';
import { type NewUserInput, createUser } from '../../src/seed.js';

export interface TestApp {
  app: FastifyInstance;
  db: DB;
  sqlite: Sqlite;
}

export async function buildTestApp(): Promise<TestApp> {
  const { sqlite, db } = openDatabase(':memory:');
  const app = await buildApp({ sqlite, db, logger: false });
  await app.ready();
  return { app, db, sqlite };
}

export const TEST_CREDS: NewUserInput = {
  username: 'alice',
  email: 'alice@example.com',
  password: 'Sup3r!secret',
};

export interface LoggedIn {
  user: { id: string; username: string; email: string; is_admin: number };
  cookie: string; // 'tdx_session=<signed>'
}

export async function createAndLogin(
  app: FastifyInstance,
  db: DB,
  creds: NewUserInput = TEST_CREDS,
  opts: { isAdmin?: boolean } = { isAdmin: true },
): Promise<LoggedIn> {
  const user = await createUser(db, creds, opts);
  const cookie = await login(app, creds.username, creds.password);
  return { user, cookie };
}

export async function login(
  app: FastifyInstance,
  username: string,
  password: string,
): Promise<string> {
  const res = await app.inject({
    method: 'POST',
    url: '/api/auth/login',
    payload: { username, password },
  });
  if (res.statusCode !== 200) throw new Error(`login failed (${res.statusCode}): ${res.body}`);
  const c = res.cookies.find((x) => x.name === 'tdx_session');
  if (!c) throw new Error('no session cookie set on login');
  return `${c.name}=${c.value}`;
}

// app.ts — D1 service. Wires Fastify + TypeBox + OpenAPI/Swagger, the DB + auth
// plugins, and the domain route modules. `buildApp(opts)` accepts an injected DB
// handle so tests run against a fresh in-memory database.

import 'dotenv/config';
import path from 'node:path';
import { fileURLToPath } from 'node:url';
import fastifyStatic from '@fastify/static';
import fastifySwagger from '@fastify/swagger';
import fastifySwaggerUi from '@fastify/swagger-ui';
import { Type, type TypeBoxTypeProvider } from '@fastify/type-provider-typebox';
import Fastify, { type FastifyInstance } from 'fastify';
import { type Backups, createBackups } from './backup.js';
import { type DB, DEFAULT_DB_PATH, type Sqlite, openDatabase } from './db.js';
import { registerAuth } from './plugins/auth.js';
import { registerDb } from './plugins/db.js';
import adminRoutes from './routes/admin.js';
import authRoutes from './routes/auth.js';
import backupRoutes from './routes/backup.js';
import bootstrapRoutes from './routes/bootstrap.js';
import eventRoutes from './routes/events.js';
import labelRoutes from './routes/labels.js';
import linkRoutes from './routes/links.js';
import noteRoutes from './routes/notes.js';
import projectRoutes from './routes/projects.js';
import queryRoutes from './routes/query.js';
import savedQueryRoutes from './routes/savedQueries.js';
import taskRoutes from './routes/tasks.js';
import tokenRoutes from './routes/tokens.js';
import { migrateVaultLayout } from './services/notes.js';

declare module 'fastify' {
  interface FastifyInstance {
    backups: Backups;
  }
}

// FRONTEND_DIR is overridable so the compiled image (dist/) can point at the
// right path; the default works for `tsx src/app.ts` in dev.
const FRONTEND_DIR =
  process.env.FRONTEND_DIR ||
  path.resolve(path.dirname(fileURLToPath(import.meta.url)), '..', '..', 'frontend');

export interface AppOpts {
  db?: DB;
  sqlite?: Sqlite;
  dbPath?: string;
  logger?: boolean;
  serveFrontend?: boolean; // serve ../../frontend statically (default true)
}

export async function buildApp(opts: AppOpts = {}): Promise<FastifyInstance> {
  const handle =
    opts.db && opts.sqlite
      ? { db: opts.db, sqlite: opts.sqlite }
      : openDatabase(opts.dbPath ?? DEFAULT_DB_PATH);

  const app = Fastify({ logger: opts.logger ?? true }).withTypeProvider<TypeBoxTypeProvider>();

  await app.register(fastifySwagger, {
    openapi: { info: { title: 'tdx API', version: '0.0.0', description: 'D1 backend' } },
  });
  await app.register(fastifySwaggerUi, { routePrefix: '/docs' });

  registerDb(app, handle);
  await migrateVaultLayout(handle.db); // one-time: move legacy flat notes into per-owner subdirs
  await registerAuth(app);
  app.decorate('backups', createBackups(handle.sqlite));

  await app.register(authRoutes);
  await app.register(adminRoutes);
  await app.register(tokenRoutes);
  await app.register(bootstrapRoutes);
  await app.register(queryRoutes);
  await app.register(taskRoutes);
  await app.register(eventRoutes);
  await app.register(linkRoutes);
  await app.register(noteRoutes);
  await app.register(projectRoutes);
  await app.register(labelRoutes);
  await app.register(savedQueryRoutes);
  await app.register(backupRoutes);

  app.get(
    '/health',
    {
      schema: {
        description: 'Liveness probe',
        response: {
          200: Type.Object({
            status: Type.Literal('ok'),
            service: Type.String(),
            time: Type.String(),
          }),
        },
      },
    },
    async () => ({ status: 'ok' as const, service: 'tdx-server', time: new Date().toISOString() }),
  );

  // Serve the no-build Vue frontend same-origin (so its relative /api/... calls
  // and the session cookie just work). API/docs/health routes are registered
  // above and take precedence over the static wildcard.
  if (opts.serveFrontend ?? true) {
    await app.register(fastifyStatic, { root: FRONTEND_DIR, index: 'index.html' });
  }

  return app;
}

// Run the server when invoked directly; stay importable (no listen) for tests.
const invokedDirectly =
  process.argv[1] && path.resolve(process.argv[1]) === fileURLToPath(import.meta.url);
if (invokedDirectly) {
  const app = await buildApp();
  const port = Number(process.env.PORT || 3002);
  const host = process.env.HOST || '0.0.0.0';
  try {
    await app.listen({ port, host });
    app.backups.init(); // arm the daily backup scheduler (real boot only, not tests)
  } catch (err) {
    app.log.error(err);
    process.exit(1);
  }
}

// backup.ts — scheduled, consistent backups of the whole SQLite database.
// TypeScript port of backend/src/backup.js. Uses the raw better-sqlite3 handle:
// `sqlite.backup()` is an online backup (consistent mid-write, no WAL hazard).
// State lives in the single-row backup_config table (seeded in 001_init.sql).
// A factory holds the daily timer so the instance owns its scheduler.

import fs from 'node:fs';
import path from 'node:path';
import Database from 'better-sqlite3';
import type { BackupConfigTable, Sqlite } from './db.js';

export const BACKUP_RE = /^tdx-\d{8}-\d{6}\.db$/; // tdx-YYYYMMDD-HHmmss.db
const STALE_MS = 25 * 60 * 60 * 1000; // missed-run threshold on boot (>25h)
const BROWSE_MAX = 500;

export interface BackupFile {
  name: string;
  size: number;
  mtime: string;
}
export interface ConfigPatch {
  enabled?: boolean;
  dir?: string;
  time_of_day?: string;
  retention?: number;
}
export interface Backups {
  getConfig(): BackupConfigTable;
  updateConfig(patch: ConfigPatch): BackupConfigTable;
  probeDir(dir: string): { ok: true; count: number } | { ok: false; error: string };
  browseDir(input?: string): Record<string, unknown>;
  listBackups(dir: string): BackupFile[];
  runBackup(): Promise<{ name: string }>;
  init(): void;
}

const pad = (n: number): string => String(n).padStart(2, '0');
// local timestamp (process TZ) so filenames sort chronologically
function stamp(d: Date): string {
  return `${d.getFullYear()}${pad(d.getMonth() + 1)}${pad(d.getDate())}-${pad(d.getHours())}${pad(d.getMinutes())}${pad(d.getSeconds())}`;
}

export function createBackups(sqlite: Sqlite): Backups {
  let timer: NodeJS.Timeout | null = null;

  const getConfig = (): BackupConfigTable =>
    sqlite.prepare('SELECT * FROM backup_config WHERE id = 1').get() as BackupConfigTable;

  function recordRun(status: string, error: string | null, when?: Date): void {
    sqlite
      .prepare(
        'UPDATE backup_config SET last_run_at = ?, last_status = ?, last_error = ? WHERE id = 1',
      )
      .run((when || new Date()).toISOString(), status, error || null);
  }

  function listBackups(dir: string): BackupFile[] {
    let names: string[] = [];
    try {
      names = fs.readdirSync(dir);
    } catch {
      return [];
    }
    return names
      .filter((n) => BACKUP_RE.test(n))
      .sort()
      .reverse()
      .map((name) => {
        const st = fs.statSync(path.join(dir, name));
        return { name, size: st.size, mtime: st.mtime.toISOString() };
      });
  }

  function probeDir(dir: string): { ok: true; count: number } | { ok: false; error: string } {
    try {
      fs.mkdirSync(dir, { recursive: true });
      const probe = path.join(dir, '.tdx-write-test');
      fs.writeFileSync(probe, 'ok');
      fs.unlinkSync(probe);
      return { ok: true, count: listBackups(dir).length };
    } catch (e) {
      return { ok: false, error: (e as Error).message };
    }
  }

  // Read-only filesystem browser for the UI's directory picker (admin-only).
  function browseDir(input?: string): Record<string, unknown> {
    const dir = path.resolve(
      input && String(input).trim() ? String(input).trim() : getConfig().dir,
    );
    let dirents: fs.Dirent[];
    try {
      dirents = fs.readdirSync(dir, { withFileTypes: true });
    } catch (e) {
      const err = e as NodeJS.ErrnoException;
      const msg =
        err.code === 'ENOENT'
          ? 'no such directory'
          : err.code === 'ENOTDIR'
            ? 'not a directory'
            : err.code === 'EACCES'
              ? 'permission denied'
              : err.message;
      return { ok: false, path: dir, error: msg };
    }
    const truncated = dirents.length > BROWSE_MAX;
    const entries = dirents
      .slice(0, BROWSE_MAX)
      .map((d) => {
        const full = path.join(dir, d.name);
        let type = d.isDirectory() ? 'dir' : 'file';
        let size: number | null = null;
        let mtime: string | null = null;
        try {
          const st = fs.statSync(full); // follows symlinks
          if (st.isDirectory()) type = 'dir';
          size = st.size;
          mtime = st.mtime.toISOString();
        } catch {
          /* unreadable entry — keep the dirent's type */
        }
        return { name: d.name, type, size, mtime };
      })
      .sort((a, b) =>
        a.type === b.type ? a.name.localeCompare(b.name) : a.type === 'dir' ? -1 : 1,
      );

    let writable = false;
    try {
      fs.accessSync(dir, fs.constants.W_OK);
      writable = true;
    } catch {
      /* read-only */
    }
    const parent = path.dirname(dir);
    return {
      ok: true,
      path: dir,
      parent: parent === dir ? null : parent,
      writable,
      truncated,
      entries,
    };
  }

  function prune(dir: string, retention: number): void {
    const keep = Math.max(1, Number(retention) || 1);
    for (const f of listBackups(dir).slice(keep)) {
      for (const ext of ['', '-wal', '-shm']) {
        try {
          fs.unlinkSync(path.join(dir, f.name + ext));
        } catch {
          /* best effort */
        }
      }
    }
  }

  async function runBackup(): Promise<{ name: string }> {
    const cfg = getConfig();
    const probe = probeDir(cfg.dir);
    if (!probe.ok) {
      recordRun('error', `directory not writable: ${probe.error}`);
      throw new Error(probe.error);
    }
    const now = new Date();
    const name = `tdx-${stamp(now)}.db`;
    const dest = path.join(cfg.dir, name);
    try {
      await sqlite.backup(dest); // online backup — consistent mid-write
      // db.backup() inherits WAL mode; collapse the copy into a standalone file.
      const copy = new Database(dest);
      copy.pragma('wal_checkpoint(TRUNCATE)');
      copy.pragma('journal_mode = DELETE');
      copy.close();
      prune(cfg.dir, cfg.retention);
      recordRun('ok', null, now);
      return { name };
    } catch (e) {
      recordRun('error', (e as Error).message, now);
      throw e;
    }
  }

  // next local HH:MM strictly after `from`
  function nextFire(timeOfDay: string, from: Date): Date {
    const [hh, mm] = String(timeOfDay).split(':').map(Number);
    const at = new Date(from);
    at.setHours(hh || 0, mm || 0, 0, 0);
    if (at <= from) at.setDate(at.getDate() + 1);
    return at;
  }

  // (re)arm the single daily timer from current config
  function arm(): void {
    if (timer) {
      clearTimeout(timer);
      timer = null;
    }
    const cfg = getConfig();
    if (!cfg || !cfg.enabled) {
      sqlite.prepare('UPDATE backup_config SET next_run_at = NULL WHERE id = 1').run();
      return;
    }
    const at = nextFire(cfg.time_of_day, new Date());
    sqlite.prepare('UPDATE backup_config SET next_run_at = ? WHERE id = 1').run(at.toISOString());
    timer = setTimeout(() => {
      runBackup()
        .catch(() => {
          /* status recorded; one bad night must not stop the timer */
        })
        .finally(arm);
    }, at.getTime() - Date.now());
    timer.unref(); // don't keep the process alive solely for the backup timer
  }

  function updateConfig(patch: ConfigPatch): BackupConfigTable {
    const cur = getConfig();
    const next = {
      enabled: patch.enabled != null ? (patch.enabled ? 1 : 0) : cur.enabled,
      dir: patch.dir != null ? String(patch.dir) : cur.dir,
      time_of_day: patch.time_of_day != null ? String(patch.time_of_day) : cur.time_of_day,
      retention: patch.retention != null ? Number(patch.retention) : cur.retention,
    };
    sqlite
      .prepare(
        'UPDATE backup_config SET enabled = ?, dir = ?, time_of_day = ?, retention = ? WHERE id = 1',
      )
      .run(next.enabled, next.dir, next.time_of_day, next.retention);
    arm();
    return getConfig();
  }

  // Called once on real server boot: arm the timer, and run immediately if a
  // scheduled run was missed while the container was down.
  function init(): void {
    const cfg = getConfig();
    if (cfg?.enabled) {
      const stale = !cfg.last_run_at || Date.now() - new Date(cfg.last_run_at).getTime() > STALE_MS;
      if (stale) {
        runBackup()
          .catch(() => {})
          .finally(arm);
        return;
      }
    }
    arm();
  }

  return { getConfig, updateConfig, probeDir, browseDir, listBackups, runBackup, init };
}

// db.ts — open SQLite (better-sqlite3), run the numbered .sql migrations, and
// expose a typed Kysely instance. Ported from backend/src/db.js; the migration
// runner is the same apply-in-order + schema_migrations pattern.

import fs from 'node:fs';
import path from 'node:path';
import { fileURLToPath } from 'node:url';
import Database from 'better-sqlite3';
import { Kysely, SqliteDialect } from 'kysely';

const __dirname = path.dirname(fileURLToPath(import.meta.url));

export const DEFAULT_DB_PATH =
  process.env.DB_PATH || path.join(__dirname, '..', 'data', 'tdx.dev.db');
// overridable so the compiled image (dist/) can point at the copied .sql files
export const MIGRATIONS_DIR =
  process.env.MIGRATIONS_DIR || path.join(__dirname, '..', 'migrations');

// ---- Kysely schema types ---------------------------------------------------
// SQLite has no boolean type; 0/1 integers are typed as `number`. Nullable
// columns are `T | null`. These mirror migrations/001_init.sql exactly.

export interface UsersTable {
  id: string;
  username: string;
  email: string;
  password_hash: string;
  theme: string | null;
  week_start: number;
  sort_prefs: string | null;
  fib_sizing: number;
  is_admin: number;
  created_at: string;
  updated_at: string;
}

export interface SessionsTable {
  id: string;
  user_id: string;
  created_at: string;
  expires_at: string;
  last_seen: string | null;
}

export interface ProjectsTable {
  id: string;
  owner_id: string;
  parent_id: string | null;
  name: string;
  color: string;
  glyph: string;
  collapsed: number;
  position: number;
  archived: number;
  health: string;
  created_at: string;
  updated_at: string;
}

export interface TasksTable {
