export type Sqlite = Database.Database;
export type DB = Kysely<Database_>;

// ---- migration runner ------------------------------------------------------
// Applies every *.sql file in migrations/ not yet recorded, in name order, each
// in its own transaction. Idempotent: re-running applies nothing new.
export function applyMigrations(sqlite: Sqlite, migrationsDir = MIGRATIONS_DIR): string[] {
  sqlite.exec(`CREATE TABLE IF NOT EXISTS schema_migrations (
    version    TEXT PRIMARY KEY,
    applied_at TEXT NOT NULL
  );`);

  const applied = new Set(
    sqlite
      .prepare('SELECT version FROM schema_migrations')
      .all()
      .map((r) => (r as { version: string }).version),
  );

  const files = fs
    .readdirSync(migrationsDir)
    .filter((f) => f.endsWith('.sql'))
    .sort();

  const record = sqlite.prepare(
    'INSERT INTO schema_migrations (version, applied_at) VALUES (?, ?)',
  );
  const newlyApplied: string[] = [];

  for (const file of files) {
    if (applied.has(file)) continue;
    const sql = fs.readFileSync(path.join(migrationsDir, file), 'utf8');
    sqlite.transaction(() => {
      sqlite.exec(sql);
      record.run(file, new Date().toISOString());
    })();
    newlyApplied.push(file);
  }
  return newlyApplied;
}

// Open a database file (or ':memory:'), set pragmas, migrate, and wrap in Kysely.
export function openDatabase(dbPath = DEFAULT_DB_PATH): { sqlite: Sqlite; db: DB } {
  if (dbPath !== ':memory:') fs.mkdirSync(path.dirname(dbPath), { recursive: true });
  const sqlite = new Database(dbPath);
  sqlite.pragma('journal_mode = WAL');
  sqlite.pragma('foreign_keys = ON');
  sqlite.pragma('synchronous = NORMAL');
  applyMigrations(sqlite);
  const db = new Kysely<Database_>({ dialect: new SqliteDialect({ database: sqlite }) });
  return { sqlite, db };
}

// `tsx src/db.ts --migrate` — apply migrations to DEFAULT_DB_PATH and report.
const invokedDirectly =
  process.argv[1] && path.resolve(process.argv[1]) === fileURLToPath(import.meta.url);
if (invokedDirectly) {
  fs.mkdirSync(path.dirname(DEFAULT_DB_PATH), { recursive: true });
  const sqlite = new Database(DEFAULT_DB_PATH);
  sqlite.pragma('journal_mode = WAL');
  sqlite.pragma('foreign_keys = ON');
  const applied = applyMigrations(sqlite);
  console.log(
    applied.length ? `[db] applied: ${applied.join(', ')}` : '[db] up to date (nothing to apply)',
  );
  console.log(`[db] ${DEFAULT_DB_PATH}`);
  sqlite.close();
}

// auth plugin — registers signed cookies and decorates the authentication
// guards. Stage 1 resolves the session cookie only; Bearer/PAT support is added
// in the tokens stage (extends resolveRequestPrincipal).

import fastifyCookie from '@fastify/cookie';
import type { FastifyInstance, FastifyReply, FastifyRequest } from 'fastify';
import {
  COOKIE_NAME,
  type ResolvedPrincipal,
  type SessionUser,
  hasScope,
  resolveSession,
} from '../auth.js';
import { resolveBearer } from '../tokens.js';

declare module 'fastify' {
  interface FastifyRequest {
    user?: SessionUser;
    principal?: ResolvedPrincipal;
  }
  interface FastifyInstance {
    authenticate: (req: FastifyRequest, reply: FastifyReply) => Promise<unknown>;
    authenticateAdmin: (req: FastifyRequest, reply: FastifyReply) => Promise<unknown>;
    requireWrite: (req: FastifyRequest, reply: FastifyReply) => Promise<unknown>;
  }
}

// Resolve a request to a principal: `Authorization: Bearer <PAT>` first (scoped),
// else the signed session cookie (full scope). Returns null if unauthenticated.
async function resolveRequestPrincipal(request: FastifyRequest): Promise<ResolvedPrincipal | null> {
  const authz = request.headers.authorization;
  if (authz?.startsWith('Bearer ')) {
    return resolveBearer(request.server.db, authz.slice(7).trim());
  }
  const raw = request.cookies?.[COOKIE_NAME];
  if (!raw) return null;
  const unsigned = request.unsignCookie(raw);
  if (!unsigned.valid || !unsigned.value) return null;
  const user = await resolveSession(request.server.db, unsigned.value);
  if (!user) return null;
  return { user, scopes: ['*'], full: true };
}

function attach(request: FastifyRequest, principal: ResolvedPrincipal): void {
  request.user = principal.user;
  request.principal = principal;
}

export async function registerAuth(app: FastifyInstance): Promise<void> {
  const secret = process.env.SESSION_SECRET;
  if (!secret) throw new Error('SESSION_SECRET is not set (required for signed session cookies)');
  await app.register(fastifyCookie, { secret });

  app.decorate('authenticate', async (request: FastifyRequest, reply: FastifyReply) => {
    const principal = await resolveRequestPrincipal(request);
    if (!principal) return reply.code(401).send({ error: 'unauthorized' });
    attach(request, principal);
  });

  app.decorate('authenticateAdmin', async (request: FastifyRequest, reply: FastifyReply) => {
    const principal = await resolveRequestPrincipal(request);
    if (!principal) return reply.code(401).send({ error: 'unauthorized' });
    if (!principal.user.is_admin) return reply.code(403).send({ error: 'forbidden' });
    attach(request, principal);
  });

  // For write routes: authenticate, then require the credential carries write
  // scope (read-only PATs are rejected; sessions are full-scope).
  app.decorate('requireWrite', async (request: FastifyRequest, reply: FastifyReply) => {
    const principal = await resolveRequestPrincipal(request);
    if (!principal) return reply.code(401).send({ error: 'unauthorized' });
    if (!hasScope(principal, 'write')) return reply.code(403).send({ error: 'insufficient scope' });
    attach(request, principal);
  });
}

export { resolveRequestPrincipal };

// auth.ts — TypeScript port of backend/src/auth.js: argon2 hashing, DB-backed
// sessions, validators, in-memory login rate-limiting, and the publicUser shape.
// The legacy module closed over a `db` global; here every DB-touching function
// takes the Kysely handle explicitly. Constants/encodings are unchanged so
// existing cookies stay valid across cutover.

import crypto from 'node:crypto';
import { Algorithm, hash, verify } from '@node-rs/argon2';
import type { DB } from './db.js';

// ---- password hashing (argon2id, OWASP-aligned) ----------------------------
const ARGON_OPTS = {
  algorithm: Algorithm.Argon2id,
  memoryCost: 19456,
  timeCost: 2,
  parallelism: 1,
};
export const hashPassword = (plain: string): Promise<string> => hash(plain, ARGON_OPTS);
export const verifyPassword = (hashed: string, plain: string): Promise<boolean> =>
  verify(hashed, plain).catch(() => false);

// A throwaway hash so login can run a verify even for an unknown username,
// keeping response time roughly constant (no user-enumeration timing leak).
let _dummyHash: string | null = null;
export async function dummyVerify(plain: string): Promise<void> {
  if (!_dummyHash) _dummyHash = await hashPassword('timing-equalizer');
  await verifyPassword(_dummyHash, plain);
}

// ---- session tokens --------------------------------------------------------
export const SESSION_TTL_MS = 30 * 24 * 60 * 60 * 1000; // 30 days, sliding
export const COOKIE_NAME = 'tdx_session';

const mintToken = (): string => crypto.randomBytes(32).toString('base64url'); // -> cookie
const hashToken = (t: string): string => crypto.createHash('sha256').update(t).digest('hex'); // -> sessions.id

// The user row the session resolves to (raw DB shape: 0/1 ints, JSON string).
export interface SessionUser {
  id: string;
  username: string;
  email: string;
  theme: string | null;
  week_start: number;
  sort_prefs: string | null;
  fib_sizing: number;
  is_admin: number;
}

export async function createSession(db: DB, userId: string): Promise<string> {
  const token = mintToken();
  const now = new Date();
  await db
    .insertInto('sessions')
    .values({
      id: hashToken(token),
      user_id: userId,
      created_at: now.toISOString(),
      expires_at: new Date(now.getTime() + SESSION_TTL_MS).toISOString(),
      last_seen: now.toISOString(),
    })
    .execute();
  return token; // raw token goes in the cookie; only its hash is stored
}

// Resolve a raw token to its user, sliding the expiry forward. Deletes the
// session if expired. Returns the user row or null.
export async function resolveSession(db: DB, rawToken: string): Promise<SessionUser | null> {
  if (!rawToken) return null;
  const sid = hashToken(rawToken);
  const sess = await db
    .selectFrom('sessions')
    .select(['user_id', 'expires_at'])
    .where('id', '=', sid)
    .executeTakeFirst();
  if (!sess) return null;
  const now = new Date();
  if (new Date(sess.expires_at) <= now) {
    await db.deleteFrom('sessions').where('id', '=', sid).execute();
    return null;
  }
  await db
    .updateTable('sessions')
    .set({
      expires_at: new Date(now.getTime() + SESSION_TTL_MS).toISOString(),
      last_seen: now.toISOString(),
    })
    .where('id', '=', sid)
    .execute();
  const user = await db
    .selectFrom('users')
    .select([
      'id',
      'username',
      'email',
      'theme',
      'week_start',
      'sort_prefs',
      'fib_sizing',
      'is_admin',
    ])
    .where('id', '=', sess.user_id)
    .executeTakeFirst();
  return user ?? null;
}

export async function revokeSession(db: DB, rawToken: string): Promise<void> {
  await db.deleteFrom('sessions').where('id', '=', hashToken(rawToken)).execute();
}

// Revoke every session for a user except an optional one to keep (the current).
export async function revokeUserSessions(
  db: DB,
  userId: string,
  keepRawToken?: string | null,
): Promise<void> {
  let q = db.deleteFrom('sessions').where('user_id', '=', userId);
  if (keepRawToken) q = q.where('id', '!=', hashToken(keepRawToken));
  await q.execute();
}

// ---- validators ------------------------------------------------------------
export type ValidationResult = { ok: true; value: string } | { ok: false; error: string };

export function validateUsername(raw: unknown): ValidationResult {
  const value = String(raw ?? '').trim();
  if (value.length < 1 || value.length > 32)
    return { ok: false, error: 'username must be 1–32 characters' };
  return { ok: true, value };
}
export function validateEmail(raw: unknown): ValidationResult {
  const value = String(raw ?? '').trim();
  if (!/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(value))
    return { ok: false, error: 'enter a valid email address' };
  return { ok: true, value };
}
export function validatePassword(raw: unknown): ValidationResult {
  const value = String(raw ?? '');
  if (value.length < 8) return { ok: false, error: 'password must be at least 8 characters' };
  if (!/[A-Z]/.test(value)) return { ok: false, error: 'password needs an uppercase letter' };
  if (!/[a-z]/.test(value)) return { ok: false, error: 'password needs a lowercase letter' };
  if (!/[0-9]/.test(value)) return { ok: false, error: 'password needs a number' };
  if (!/[^A-Za-z0-9]/.test(value)) return { ok: false, error: 'password needs a symbol' };
  return { ok: true, value };
}

// validate + normalize a client sort_prefs object → clean {order,enabled,dirs}
// (or null). Returns undefined if the payload is malformed.
const SORT_KEYS = ['due', 'created', 'title', 'project', 'priority', 'tag'];
export interface SortPrefs {
  order: string[];
  enabled: Record<string, boolean>;
  dirs: Record<string, 'asc' | 'desc'>;
}
export function cleanSortPrefs(p: unknown): SortPrefs | null | undefined {
  if (p === null) return null;
  if (typeof p !== 'object' || Array.isArray(p)) return undefined;
  const o = p as {
    order?: unknown;
    enabled?: Record<string, unknown>;
    dirs?: Record<string, unknown>;
  };
  const order = Array.isArray(o.order) ? o.order.filter((k) => SORT_KEYS.includes(k)) : [];
  for (const k of SORT_KEYS) if (!order.includes(k)) order.push(k);
  const enabled: Record<string, boolean> = {};
  const dirs: Record<string, 'asc' | 'desc'> = {};
  for (const k of SORT_KEYS) {
    enabled[k] = !(o.enabled && o.enabled[k] === false);
    dirs[k] = o.dirs && o.dirs[k] === 'desc' ? 'desc' : 'asc';
  }
  if (!SORT_KEYS.some((k) => enabled[k])) return undefined;
  return { order, enabled, dirs };
}

export interface PublicUser {
  id: string;
  username: string;
  email: string;
  theme: string;
  week_start: number;
  sort_prefs: SortPrefs | null;
  fib_sizing: boolean;
  is_admin: boolean;
}
export function publicUser(u: SessionUser): PublicUser {
  return {
    id: u.id,
    username: u.username,
    email: u.email,
    theme: u.theme || 'amber',
    week_start: u.week_start ?? 1,
    sort_prefs: u.sort_prefs ? (JSON.parse(u.sort_prefs) as SortPrefs) : null,
    fib_sizing: !!u.fib_sizing,
    is_admin: !!u.is_admin,
  };
}

// ---- principals & scopes (sessions are full-scope; PATs carry scopes) ------
export interface ResolvedPrincipal {
  user: SessionUser;
  scopes: string[];
  full: boolean; // a session: implies every scope
}
// Only the read/write suffix is enforced now; per-domain prefixes are reserved.
// Accepts '*', a bare 'read'/'write', or a domain-scoped 'tasks:read'.
export function hasScope(p: ResolvedPrincipal, action: 'read' | 'write'): boolean {
  return p.full || p.scopes.some((s) => s === '*' || s === action || s.endsWith(`:${action}`));
}

// ---- login rate-limiting (in-memory; resets on restart) --------------------
const MAX_FAILS = 5;
const WINDOW_MS = 15 * 60 * 1000;
const BLOCK_MS = 60 * 1000;
interface Attempt {
  windowStart: number;
  fails: number;
  blockedUntil: number;
}
const attempts = new Map<string, Attempt>();
const rlKey = (username: unknown, ip: string): string =>
  `${String(username || '').toLowerCase()}|${ip}`;

export function rateLimited(username: unknown, ip: string): boolean {
  const rec = attempts.get(rlKey(username, ip));
  return !!(rec && rec.blockedUntil && rec.blockedUntil > Date.now());
}
export function recordFailure(username: unknown, ip: string): void {
  const key = rlKey(username, ip);
  const now = Date.now();
  let rec = attempts.get(key);
  if (!rec || now - rec.windowStart > WINDOW_MS)
    rec = { windowStart: now, fails: 0, blockedUntil: 0 };
  rec.fails += 1;
  if (rec.fails >= MAX_FAILS) rec.blockedUntil = now + BLOCK_MS;
  attempts.set(key, rec);
}
export const clearFailures = (username: unknown, ip: string): boolean =>
  attempts.delete(rlKey(username, ip));

// tokens.ts — opaque, revocable API tokens (PATs) for CLI / MCP / agents /
// portfolio. The token is shown once; only its sha256 hash is stored. Resolves
// via `Authorization: Bearer <token>` to a (user, scopes) principal.

import crypto from 'node:crypto';
import type { ResolvedPrincipal } from './auth.js';
import type { DB } from './db.js';
import { newId } from './ids.js';

const SESSION_USER_COLS = [
  'id',
  'username',
  'email',
  'theme',
  'week_start',
  'sort_prefs',
  'fib_sizing',
  'is_admin',
] as const;

export const mintApiToken = (): string => `tdx_pat_${crypto.randomBytes(32).toString('base64url')}`;
export const hashApiToken = (t: string): string =>
  crypto.createHash('sha256').update(t).digest('hex');

export interface TokenInfo {
  id: string;
  name: string;
  scopes: string[];
  created_at: string;
  last_used_at: string | null;
  revoked_at: string | null;
}

export async function createToken(
  db: DB,
  userId: string,
  name: string,
  scopes: string[],
): Promise<{ id: string; token: string }> {
  const id = newId();
  const token = mintApiToken();
  await db
    .insertInto('api_tokens')
    .values({
      id,
      user_id: userId,
      name,
      token_hash: hashApiToken(token),
      scopes: JSON.stringify(scopes),
      created_at: new Date().toISOString(),
      last_used_at: null,
      revoked_at: null,
    })
    .execute();
  return { id, token };
}

export async function listTokens(db: DB, userId: string): Promise<TokenInfo[]> {
  const rows = await db
    .selectFrom('api_tokens')
    .select(['id', 'name', 'scopes', 'created_at', 'last_used_at', 'revoked_at'])
    .where('user_id', '=', userId)
    .orderBy('created_at')
    .execute();
  return rows.map((r) => ({ ...r, scopes: parseScopes(r.scopes) }));
}

export async function revokeToken(db: DB, userId: string, id: string): Promise<boolean> {
  const res = await db
    .updateTable('api_tokens')
    .set({ revoked_at: new Date().toISOString() })
    .where('id', '=', id)
    .where('user_id', '=', userId)
    .where('revoked_at', 'is', null)
    .executeTakeFirst();
  return Number(res.numUpdatedRows) > 0;
}

// Resolve a raw bearer token to a principal (scopes from the token, full=false).
export async function resolveBearer(db: DB, raw: string): Promise<ResolvedPrincipal | null> {
  if (!raw) return null;
  const row = await db
    .selectFrom('api_tokens')
    .select(['id', 'user_id', 'scopes', 'revoked_at'])
    .where('token_hash', '=', hashApiToken(raw))
    .executeTakeFirst();
  if (!row || row.revoked_at) return null;
  const user = await db
    .selectFrom('users')
    .select(SESSION_USER_COLS)
    .where('id', '=', row.user_id)
    .executeTakeFirst();
  if (!user) return null;
  await db
    .updateTable('api_tokens')
    .set({ last_used_at: new Date().toISOString() })
    .where('id', '=', row.id)
    .execute();
  return { user, scopes: parseScopes(row.scopes), full: false };
}

function parseScopes(s: string): string[] {
  try {
    const v = JSON.parse(s);
    return Array.isArray(v) ? v.map(String) : [];
  } catch {
    return [];
  }
}

import { randomUUID } from 'node:crypto';

// Global UUID id for every shareable resource (replaces the legacy prefixed `t_N`).
export const newId = (): string => randomUUID();

import type { FastifyInstance } from 'fastify';
import type { DB, Sqlite } from '../db.js';

declare module 'fastify' {
  interface FastifyInstance {
    db: DB;
    sqlite: Sqlite;
  }
}

// Decorate the root instance with the DB handles so routes/services reach a
// typed Kysely handle via `request.server.db` (child contexts inherit it).
export function registerDb(app: FastifyInstance, handle: { db: DB; sqlite: Sqlite }): void {
  app.decorate('db', handle.db);
  app.decorate('sqlite', handle.sqlite);
}

// routes/admin.ts — admin-only user creation (replaces tools/add-user.js).

import type { FastifyInstance } from 'fastify';
import { validateEmail, validatePassword, validateUsername } from '../auth.js';
import { createUser } from '../seed.js';

export default async function adminRoutes(app: FastifyInstance): Promise<void> {
  app.post('/api/admin/users', { preHandler: app.authenticateAdmin }, async (request, reply) => {
    const body = (request.body ?? {}) as {
      username?: unknown;
      email?: unknown;
      password?: unknown;
      isAdmin?: unknown;
    };

    const u = validateUsername(body.username);
    if (!u.ok) return reply.code(400).send({ error: u.error, field: 'username' });
    const e = validateEmail(body.email);
    if (!e.ok) return reply.code(400).send({ error: e.error, field: 'email' });
    const p = validatePassword(body.password);
    if (!p.ok) return reply.code(400).send({ error: p.error, field: 'password' });

    const clashU = await app.db
      .selectFrom('users')
      .select('id')
      .where('username', '=', u.value)
      .executeTakeFirst();
    if (clashU)
      return reply.code(409).send({ error: 'username is already taken', field: 'username' });
    const clashE = await app.db
      .selectFrom('users')
      .select('id')
      .where('email', '=', e.value)
      .executeTakeFirst();
    if (clashE) return reply.code(409).send({ error: 'email is already in use', field: 'email' });

    try {
      const created = await createUser(
        app.db,
        { username: u.value, email: e.value, password: p.value },
        { isAdmin: !!body.isAdmin },
      );
      return reply.code(201).send(created);
    } catch (err) {
      if (/UNIQUE/.test((err as Error).message))
        return reply.code(409).send({ error: 'username or email already in use' });
      throw err;
    }
  });
}

// seed.ts — user creation + per-user defaults. Replaces tools/add-user.js +
// db.seedUserDefaults. IDs are UUIDs now (the composite-PK reason for fixed
// `p_inbox`/`sv_*` ids is gone). First user (no users yet) defaults to admin.

import { hashPassword } from './auth.js';
import type { DB } from './db.js';
import { newId } from './ids.js';

export interface NewUserInput {
  username: string;
  email: string;
  password: string;
}
export interface CreatedUser {
  id: string;
  username: string;
  email: string;
  is_admin: number;
}

export async function createUser(
  db: DB,
  input: NewUserInput,
  opts: { isAdmin?: boolean } = {},
): Promise<CreatedUser> {
  const now = new Date().toISOString();
  const existing = await db.selectFrom('users').select('id').limit(1).executeTakeFirst();
  const isAdmin = opts.isAdmin ?? !existing; // first user is admin
  const id = newId();
  const password_hash = await hashPassword(input.password);
  await db
    .insertInto('users')
    .values({
      id,
      username: input.username,
      email: input.email,
      password_hash,
      theme: null,
      week_start: 1,
      sort_prefs: null,
      fib_sizing: 0,
      is_admin: isAdmin ? 1 : 0,
      created_at: now,
      updated_at: now,
    })
    .execute();
  await seedUserDefaults(db, id);
  return { id, username: input.username, email: input.email, is_admin: isAdmin ? 1 : 0 };
}

// inbox project + the 6 built-in system smart-views (same glyphs/queries/order as
// legacy db.seedUserDefaults).
export async function seedUserDefaults(db: DB, ownerId: string): Promise<void> {
  const now = new Date().toISOString();
  await db
    .insertInto('projects')
    .values({
      id: newId(),
      owner_id: ownerId,
      parent_id: null,
      name: 'inbox',
      color: '#ffb000',
      glyph: '⌂',
      collapsed: 0,
      position: 0,
      archived: 0,
      health: '[]',
      created_at: now,
      updated_at: now,
    })
    .execute();

  const views: [string, string, string, number, number][] = [
    ['Today', '☉', 'status:open due:today', 0, 0],
    ['Open', '○', 'status:open', 1, 1],
    ['Overdue', '!', 'status:overdue', 2, 1],
    ['This week', '☰', 'status:open due:week', 3, 0],
    ['Recurring', '↻', 'recurring:true status:open', 4, 0],
    ['No date', '∅', 'due:none status:open', 5, 0],
  ];
  for (const [name, glyph, query, position, pinned] of views) {
    await db
      .insertInto('saved_queries')
      .values({
        id: newId(),
        owner_id: ownerId,
        name,
        glyph,
        query,
        system: 1,
        color: null,
        position,
        pinned,
      })
      .execute();
  }
}

// routes/auth.ts — login / logout / me / account. Faithful port of
// backend/src/routes/auth.js using Kysely + the ported auth module.

import type { FastifyInstance } from 'fastify';
import {
  COOKIE_NAME,
  type PublicUser,
  SESSION_TTL_MS,
  cleanSortPrefs,
  clearFailures,
  createSession,
  dummyVerify,
  hashPassword,
  publicUser,
  rateLimited,
  recordFailure,
  resolveSession,
  revokeSession,
  revokeUserSessions,
  validateEmail,
  validatePassword,
  validateUsername,
  verifyPassword,
} from '../auth.js';

const COOKIE_OPTS = {
  httpOnly: true,
  sameSite: 'strict' as const,
  secure: false, // plain HTTP over LAN; revisit behind HTTPS
  path: '/',
  signed: true,
  maxAge: Math.floor(SESSION_TTL_MS / 1000),
};

const ALLOWED_THEMES = ['amber', 'matrix', 'ice', 'paper', 'plasma', 'magenta'];
const WEEK_STARTS = [0, 1, 2, 3, 4, 5, 6];

export default async function authRoutes(app: FastifyInstance): Promise<void> {
  // ---- login --------------------------------------------------------------
  app.post('/api/auth/login', async (request, reply) => {
    const { username, password } = (request.body ?? {}) as { username?: string; password?: string };
    const ip = request.ip;
    const GENERIC = { error: 'invalid username or password' };

    if (rateLimited(username, ip)) {
      return reply.code(429).send({ error: 'too many attempts — try again shortly' });
    }
    if (!username || !password) {
      recordFailure(username, ip);
      return reply.code(401).send(GENERIC);
    }

    const user = await app.db
      .selectFrom('users')
      .selectAll()
      .where('username', '=', String(username).trim()) // column is COLLATE NOCASE
      .executeTakeFirst();
    if (!user) {
      await dummyVerify(String(password)); // equalize timing
      recordFailure(username, ip);
      return reply.code(401).send(GENERIC);
    }
    const ok = await verifyPassword(user.password_hash, String(password));
    if (!ok) {
      recordFailure(username, ip);
      return reply.code(401).send(GENERIC);
    }

    clearFailures(username, ip);
    const token = await createSession(app.db, user.id);
    reply.setCookie(COOKIE_NAME, token, COOKIE_OPTS);
    return publicUser(user);
  });

  // ---- logout -------------------------------------------------------------
  app.post('/api/auth/logout', { preHandler: app.authenticate }, async (request, reply) => {
    const raw = request.cookies[COOKIE_NAME];
    const unsigned = raw ? request.unsignCookie(raw) : null;
    if (unsigned?.valid && unsigned.value) await revokeSession(app.db, unsigned.value);
    reply.clearCookie(COOKIE_NAME, { path: '/' });
    return { ok: true };
  });

  // ---- me -----------------------------------------------------------------
  app.get('/api/auth/me', { preHandler: app.authenticate }, async (request) => {
    return publicUser(request.user!);
  });

  // ---- account update -----------------------------------------------------
  app.put('/api/auth/account', { preHandler: app.authenticate }, async (request, reply) => {
    const body = (request.body ?? {}) as Record<string, unknown>;
    const userId = request.user!.id;
    const current = await app.db
      .selectFrom('users')
      .selectAll()
      .where('id', '=', userId)
      .executeTakeFirst();
    if (!current) return reply.code(401).send({ error: 'unauthorized' });

    let username = current.username;
    let email = current.email;
    let passwordHash = current.password_hash;
    let theme = current.theme || 'amber';
    let weekStart = current.week_start ?? 1;
    let sortPrefs = current.sort_prefs ?? null; // JSON string or null
    let fibSizing = current.fib_sizing ?? 0;

    if (body.theme !== undefined) {
      if (!ALLOWED_THEMES.includes(body.theme as string))
        return reply.code(400).send({ error: 'unknown theme', field: 'theme' });
      theme = body.theme as string;
    }
    if (body.sort_prefs !== undefined) {
      const clean = cleanSortPrefs(body.sort_prefs);
      if (clean === undefined)
        return reply.code(400).send({ error: 'invalid sort prefs', field: 'sort_prefs' });
      sortPrefs = clean === null ? null : JSON.stringify(clean);
    }
    if (body.week_start !== undefined) {
      if (!WEEK_STARTS.includes(Number(body.week_start)))
        return reply.code(400).send({ error: 'invalid week start', field: 'week_start' });
      weekStart = Number(body.week_start);
    }
    if (body.fib_sizing !== undefined) {
      const v = Number(body.fib_sizing);
      if (![0, 1].includes(v))
        return reply.code(400).send({ error: 'invalid fib_sizing', field: 'fib_sizing' });
      fibSizing = v;
    }
    if (body.username !== undefined) {
      const v = validateUsername(body.username);
      if (!v.ok) return reply.code(400).send({ error: v.error, field: 'username' });
      const clash = await app.db
        .selectFrom('users')
        .select('id')
        .where('username', '=', v.value)
        .where('id', '!=', userId)
        .executeTakeFirst();
      if (clash)
        return reply.code(409).send({ error: 'username is already taken', field: 'username' });
      username = v.value;
    }
    if (body.email !== undefined) {
      const v = validateEmail(body.email);
      if (!v.ok) return reply.code(400).send({ error: v.error, field: 'email' });
      const clash = await app.db
        .selectFrom('users')
        .select('id')
        .where('email', '=', v.value)
        .where('id', '!=', userId)
        .executeTakeFirst();
      if (clash) return reply.code(409).send({ error: 'email is already in use', field: 'email' });
      email = v.value;
    }

    let passwordChanged = false;
    if (body.newPassword !== undefined || body.oldPassword !== undefined) {
      const okOld = await verifyPassword(current.password_hash, String(body.oldPassword || ''));
      if (!okOld)
        return reply
          .code(400)
          .send({ error: 'current password is incorrect', field: 'oldPassword' });
      const v = validatePassword(body.newPassword);
      if (!v.ok) return reply.code(400).send({ error: v.error, field: 'newPassword' });
      if (await verifyPassword(current.password_hash, v.value)) {
        return reply
          .code(400)
          .send({ error: 'new password must differ from the current one', field: 'newPassword' });
      }
      passwordHash = await hashPassword(v.value);
      passwordChanged = true;
    }

    const now = new Date().toISOString();
    try {
      await app.db
        .updateTable('users')
        .set({
          username,
          email,
          password_hash: passwordHash,
          theme,
          week_start: weekStart,
          sort_prefs: sortPrefs,
          fib_sizing: fibSizing,
          updated_at: now,
        })
        .where('id', '=', userId)
        .execute();
    } catch (err) {
      if (/UNIQUE/.test((err as Error).message))
        return reply.code(409).send({ error: 'username or email already in use' });
      throw err;
    }

    if (passwordChanged) {
      const raw = request.cookies[COOKIE_NAME];
      const unsigned = raw ? request.unsignCookie(raw) : null;
      await revokeUserSessions(app.db, userId, unsigned?.valid ? unsigned.value : null);
    }

    const result: PublicUser = publicUser({
      id: userId,
      username,
      email,
      theme,
      week_start: weekStart,
      sort_prefs: sortPrefs,
      fib_sizing: fibSizing,
      is_admin: current.is_admin,
    });
    return result;
  });
}

