// bootstrap.ts — the per-owner read of all live (non-archived) entities the SPA
// needs to render. The legacy readState shape, minus version/seq, per-owner.

import type { DB } from '../db.js';
import { type TaskJson, rowToLabel, rowToProject, rowToSavedQuery, rowToTask } from '../schemas.js';

export interface Bootstrap {
  projects: ReturnType<typeof rowToProject>[];
  tasks: TaskJson[];
  labels: ReturnType<typeof rowToLabel>[];
  savedQueries: ReturnType<typeof rowToSavedQuery>[];
}

export async function readBootstrap(db: DB, ownerId: string): Promise<Bootstrap> {
  const projects = await db
    .selectFrom('projects')
    .selectAll()
    .where('owner_id', '=', ownerId)
    .where('archived', '=', 0)
    .orderBy('position')
    .orderBy('id')
    .execute();
  const tasks = await db
    .selectFrom('tasks')
    .selectAll()
    .where('owner_id', '=', ownerId)
    .where('archived', '=', 0)
    .orderBy('position')
    .orderBy('id')
    .execute();
  const labels = await db
    .selectFrom('labels')
    .selectAll()
    .where('owner_id', '=', ownerId)
    .orderBy('name')
    .orderBy('id')
    .execute();
  const savedQueries = await db
    .selectFrom('saved_queries')
    .selectAll()
    .where('owner_id', '=', ownerId)
    .orderBy('position')
    .orderBy('id')
    .execute();

  // labels per (non-archived) task, in a single pass; deterministic by label_id
  const tls = await db
    .selectFrom('task_labels')
    .innerJoin('tasks', 'tasks.id', 'task_labels.task_id')
    .select(['task_labels.task_id', 'task_labels.label_id'])
    .where('tasks.owner_id', '=', ownerId)
    .where('tasks.archived', '=', 0)
    .orderBy('task_labels.label_id')
    .execute();
  const byTask = new Map<string, string[]>();
  for (const tl of tls) {
    const a = byTask.get(tl.task_id) ?? [];
    a.push(tl.label_id);
    byTask.set(tl.task_id, a);
  }

  return {
    projects: projects.map(rowToProject),
    tasks: tasks.map((t) => rowToTask(t, byTask.get(t.id) ?? [])),
    labels: labels.map(rowToLabel),
    savedQueries: savedQueries.map(rowToSavedQuery),
  };
}

// routes/events.ts — event CRUD + the calendar range read. Mirrors routes/tasks.ts.
// Events are owner-only. Writes need write scope + write access and honor If-Match.

import type { FastifyInstance } from 'fastify';
import {
  EventCreateSchema,
  EventRangeQuerySchema,
  EventRangeResponseSchema,
  EventUpdateSchema,
} from '../schemas.js';
import { PreconditionFailed, etag } from '../services/concurrency.js';
import {
  archiveEvent,
  createEvent,
  eventsInRange,
  getEvent,
  updateEvent,
} from '../services/events.js';
import { denyAccess, ifMatchOf } from './_access.js';

export default async function eventRoutes(app: FastifyInstance): Promise<void> {
  app.post(
    '/api/events',
    { preHandler: app.requireWrite, schema: { body: EventCreateSchema } },
    async (request, reply) => {
      const event = await createEvent(
        app.db,
        request.user!.id,
        request.body as Parameters<typeof createEvent>[2],
      );
      return reply.code(201).header('etag', etag(event.updatedAt)).send(event);
    },
  );

  // calendar range read (owner-scoped) — recurring events expanded into occurrences
  app.get(
    '/api/events',
    {
      preHandler: app.authenticate,
      schema: { querystring: EventRangeQuerySchema, response: { 200: EventRangeResponseSchema } },
    },
    async (request) => {
      const { from, to } = request.query as { from: string; to: string };
      return { occurrences: await eventsInRange(app.db, request.user!.id, from, to) };
    },
  );

  app.get('/api/events/:id', { preHandler: app.authenticate }, async (request, reply) => {
    const { id } = request.params as { id: string };
    if (await denyAccess(app, request, reply, 'event', id, 'read')) return;
    const event = await getEvent(app.db, request.user!.id, id);
    if (!event) return reply.code(404).send({ error: 'not found' });
    return reply.header('etag', etag(event.updatedAt)).send(event);
  });

  app.put(
    '/api/events/:id',
    { preHandler: app.requireWrite, schema: { body: EventUpdateSchema } },
    async (request, reply) => {
      const { id } = request.params as { id: string };
      if (await denyAccess(app, request, reply, 'event', id, 'write')) return;
      try {
        const event = await updateEvent(
          app.db,
          request.user!.id,
          id,
          request.body as Parameters<typeof updateEvent>[3],
          ifMatchOf(request),
        );
        if (!event) return reply.code(404).send({ error: 'not found' });
        return reply.header('etag', etag(event.updatedAt)).send(event);
      } catch (err) {
        if (err instanceof PreconditionFailed) {
          return reply
            .code(412)
            .send({ error: 'stale', current: await getEvent(app.db, request.user!.id, id) });
        }
        throw err;
      }
    },
  );

  app.delete('/api/events/:id', { preHandler: app.requireWrite }, async (request, reply) => {
    const { id } = request.params as { id: string };
    if (await denyAccess(app, request, reply, 'event', id, 'write')) return;
    await archiveEvent(app.db, request.user!.id, id);
    return reply.code(204).send();
  });
}

// concurrency.ts — minimal per-resource optimistic concurrency. ETag = the row's
// `updated_at`. A mutating request MAY send `If-Match`; if present and stale, the
// write is rejected (PreconditionFailed → 412). Absent If-Match is allowed
// (pragmatic for single-user clients that don't track ETags).

export class PreconditionFailed extends Error {
  constructor() {
    super('stale');
    this.name = 'PreconditionFailed';
  }
}

export const etag = (updatedAt: string): string => `"${updatedAt}"`;

export function checkIfMatch(ifMatch: string | undefined, current: string): void {
  if (ifMatch == null) return; // no precondition supplied
  const provided = ifMatch.replace(/^W\//, '').replace(/^"|"$/g, '');
  if (provided !== current) throw new PreconditionFailed();
}

// services/events.ts — event CRUD + the calendar's range read. Mirrors
// services/tasks.ts. Recurring events are NOT spawned; they're expanded
// virtually into occurrences within the queried window (via Rec).

import type { Updateable } from 'kysely';
import type { DB, EventsTable } from '../db.js';
import { newId } from '../ids.js';
import { Rec } from '../rec.js';
import { type EventJson, rowToEvent } from '../schemas.js';
import { checkIfMatch } from './concurrency.js';

export interface EventCreateInput {
  id?: string;
  title: string;
  notes?: string;
  location?: string | null;
  allDay?: boolean;
  startAt: string;
  endAt?: string | null;
  recurrence?: string | null;
  reminder?: string | null;
  assigneeId?: string | null;
  position?: number;
}
export interface EventPatch {
  title?: string;
  notes?: string;
  location?: string | null;
  allDay?: boolean;
  startAt?: string;
  endAt?: string | null;
  recurrence?: string | null;
  reminder?: string | null;
  assigneeId?: string | null;
  position?: number;
}
export interface EventOccurrence extends EventJson {
  date: string; // the concrete YYYY-MM-DD this occurrence falls on
}

export async function getEvent(db: DB, owner: string, id: string): Promise<EventJson | null> {
  const row = await db
    .selectFrom('events')
    .selectAll()
    .where('id', '=', id)
    .where('owner_id', '=', owner)
    .executeTakeFirst();
  return row ? rowToEvent(row) : null;
}

export async function createEvent(
  db: DB,
  owner: string,
  input: EventCreateInput,
): Promise<EventJson> {
  const id = input.id ?? newId();
  const now = new Date().toISOString();
  const m = await db
    .selectFrom('events')
    .select((eb) => eb.fn.max('position').as('m'))
    .where('owner_id', '=', owner)
    .executeTakeFirst();
  await db
    .insertInto('events')
    .values({
      id,
      owner_id: owner,
      creator_id: owner,
      assignee_id: input.assigneeId ?? null,
      title: input.title,
      notes: input.notes ?? '',
      location: input.location ?? null,
      all_day: input.allDay ? 1 : 0,
      start_at: input.startAt,
      end_at: input.endAt ?? null,
      recurrence: input.recurrence ?? null,
      reminder: input.reminder ?? null,
      position: input.position ?? Number(m?.m ?? 0) + 1,
      archived: 0,
      created_at: now,
      updated_at: now,
    })
    .execute();
  return (await getEvent(db, owner, id))!;
}

export async function updateEvent(
  db: DB,
  owner: string,
  id: string,
  patch: EventPatch,
  ifMatch?: string,
): Promise<EventJson | null> {
  return db.transaction().execute(async (trx) => {
    const row = await trx
      .selectFrom('events')
      .selectAll()
      .where('id', '=', id)
      .where('owner_id', '=', owner)
      .executeTakeFirst();
    if (!row) return null;
    checkIfMatch(ifMatch, row.updated_at);
    const set: Updateable<EventsTable> = { updated_at: new Date().toISOString() };
    if (patch.title !== undefined) set.title = patch.title;
    if (patch.notes !== undefined) set.notes = patch.notes;
    if (patch.location !== undefined) set.location = patch.location;
    if (patch.allDay !== undefined) set.all_day = patch.allDay ? 1 : 0;
    if (patch.startAt !== undefined) set.start_at = patch.startAt;
    if (patch.endAt !== undefined) set.end_at = patch.endAt;
    if (patch.recurrence !== undefined) set.recurrence = patch.recurrence;
    if (patch.reminder !== undefined) set.reminder = patch.reminder;
    if (patch.assigneeId !== undefined) set.assignee_id = patch.assigneeId;
    if (patch.position !== undefined) set.position = patch.position;
    await trx
      .updateTable('events')
      .set(set)
      .where('id', '=', id)
      .where('owner_id', '=', owner)
      .execute();
    const fresh = await trx
      .selectFrom('events')
      .selectAll()
      .where('id', '=', id)
      .executeTakeFirst();
    return rowToEvent(fresh!);
  });
}

export async function archiveEvent(db: DB, owner: string, id: string): Promise<void> {
  await db
    .updateTable('events')
    .set({ archived: 1, updated_at: new Date().toISOString() })
    .where('id', '=', id)
    .where('owner_id', '=', owner)
    .execute();
}

// The calendar's data source: every event occurrence whose date is in [from,to]
// (inclusive, YYYY-MM-DD). One-offs land on their own start date; recurring
// events are expanded across the window via Rec. Series id is preserved.
export async function eventsInRange(
  db: DB,
  owner: string,
  from: string,
  to: string,
): Promise<EventOccurrence[]> {
  const rows = await db
    .selectFrom('events')
    .selectAll()
    .where('owner_id', '=', owner)
    .where('archived', '=', 0)
    .execute();

  const out: EventOccurrence[] = [];
  const fromD = Rec.parseYMD(from) as Date;
  const toD = Rec.parseYMD(to) as Date;

  for (const row of rows) {
    const ev = rowToEvent(row);
    const startDate = ev.startAt.slice(0, 10); // YYYY-MM-DD
    const rule = ev.recurrence ? Rec.parse(ev.recurrence) : null;

    if (!rule || rule.type === 'invalid') {
      if (startDate >= from && startDate <= to) out.push({ ...ev, date: startDate });
      continue;
    }
    // expand: walk each day in the window, include matches on/after the series start
    const anchor = Rec.parseYMD(startDate) as Date;
    for (let d = new Date(fromD); d <= toD; d = Rec.addDays(d, 1)) {
      const dymd = Rec.ymd(d);
      if (dymd < startDate) continue; // before the event ever started
      if (Rec.matches(d, rule, anchor)) out.push({ ...ev, date: dymd });
    }
  }

  out.sort((a, b) => a.date.localeCompare(b.date) || a.position - b.position);
  return out;
}

// rec.ts — TypeScript port of frontend/js/recurrence.js (pure functions).
// Behavior is intended to be byte-for-byte identical (parity-tested against the
// Phase 0 goldens); only the wrapper changed (window.Rec -> exports) plus light
// types. Supported syntax is unchanged — see the original header.

export type RuleType = 'daily' | 'weekly' | 'monthly-day' | 'monthly-weekday' | 'invalid';

export interface Rule {
  type: RuleType;
  interval?: number;
  days?: number[] | null;
  day?: number | null;
  ord?: number;
  weekday?: number;
  raw?: string;
}

export interface OccurrenceOpts {
  anchor?: string | Date;
  from?: string | Date;
  count?: number;
  inclusive?: boolean;
}

const WD = ['sun', 'mon', 'tue', 'wed', 'thu', 'fri', 'sat'];
const WD_FULL = ['Sunday', 'Monday', 'Tuesday', 'Wednesday', 'Thursday', 'Friday', 'Saturday'];
const ORD: Record<string, number> = { '1st': 1, '2nd': 2, '3rd': 3, '4th': 4, '5th': 5, last: -1 };
const ORD_NAME: Record<number, string> = {
  1: '1st',
  2: '2nd',
  3: '3rd',
  4: '4th',
  5: '5th',
  '-1': 'last',
};

function pad(n: number): string {
  return String(n).padStart(2, '0');
}
export function ymd(d: Date): string {
  return `${d.getFullYear()}-${pad(d.getMonth() + 1)}-${pad(d.getDate())}`;
}
export function parseYMD(s: string | null | undefined): Date | null {
  if (!s) return null;
  const [y, m, d] = s.split('-').map(Number);
  return new Date(y, m - 1, d);
}
export function startOfDay(d: Date): Date {
  return new Date(d.getFullYear(), d.getMonth(), d.getDate());
}
export function addDays(d: Date, n: number): Date {
  const x = new Date(d);
  x.setDate(x.getDate() + n);
  return x;
}
export function daysBetween(a: Date, b: Date): number {
  return Math.round((+startOfDay(b) - +startOfDay(a)) / 86400000);
}
function sameDay(a: Date, b: Date): boolean {
  return ymd(a) === ymd(b);
}

// ---- parse -------------------------------------------------
export function parse(str: string | null | undefined): Rule | null {
  if (!str) return null;
  const s = str.trim().toLowerCase().replace(/\s+/g, ' ');
  let m: RegExpMatchArray | null;

  if (s === 'daily' || s === 'every day') return { type: 'daily', interval: 1 };

  if ((m = s.match(/^every (\d+) days?$/))) return { type: 'daily', interval: +m[1] };

  // weekly on days / every N weeks on days
  if ((m = s.match(/^weekly on (.+)$/))) return mkWeekly(1, m[1]);
  if ((m = s.match(/^every (\d+) weeks? on (.+)$/))) return mkWeekly(+m[1], m[2]);
  if ((m = s.match(/^every (\d+) weeks?$/))) return { type: 'weekly', interval: +m[1], days: null };

  // monthly on day D
  if ((m = s.match(/^monthly on day (\d+)$/)))
    return { type: 'monthly-day', interval: 1, day: clampDay(+m[1]) };
  if ((m = s.match(/^every (\d+) months? on day (\d+)$/)))
    return { type: 'monthly-day', interval: +m[1], day: clampDay(+m[2]) };

  // monthly on Nth weekday
  if ((m = s.match(/^monthly on (1st|2nd|3rd|4th|5th|last) (mon|tue|wed|thu|fri|sat|sun)$/)))
    return { type: 'monthly-weekday', interval: 1, ord: ORD[m[1]], weekday: WD.indexOf(m[2]) };
  if (
    (m = s.match(
      /^every (\d+) months? on (1st|2nd|3rd|4th|5th|last) (mon|tue|wed|thu|fri|sat|sun)$/,
    ))
  )
    return { type: 'monthly-weekday', interval: +m[1], ord: ORD[m[2]], weekday: WD.indexOf(m[3]) };

  if ((m = s.match(/^every (\d+) months?$/)))
    return { type: 'monthly-day', interval: +m[1], day: null };

  return { type: 'invalid', raw: str };
}

function clampDay(d: number): number {
  return Math.min(31, Math.max(1, d));
}

function mkWeekly(interval: number, daysStr: string): Rule {
  const days = daysStr
    .split(/[ ,]+/)
    .map((x) => WD.indexOf(x.trim()))
    .filter((i) => i >= 0)
    .sort((a, b) => a - b);
  if (!days.length) return { type: 'invalid', raw: `weekly on ${daysStr}` };
  return { type: 'weekly', interval, days };
}

// ---- stringify (canonical) --------------------------------
export function stringify(r: Rule | null): string {
  if (!r || r.type === 'invalid') return '';
  switch (r.type) {
    case 'daily':
      return r.interval === 1 ? 'daily' : `every ${r.interval} days`;
    case 'weekly': {
      const dd = r.days && r.days.length ? r.days.map((i) => WD[i]).join(',') : null;
      if (r.interval === 1) return dd ? `weekly on ${dd}` : 'weekly on mon';
      return dd ? `every ${r.interval} weeks on ${dd}` : `every ${r.interval} weeks`;
    }
    case 'monthly-day': {
      const d = r.day || 1;
      return r.interval === 1 ? `monthly on day ${d}` : `every ${r.interval} months on day ${d}`;
    }
    case 'monthly-weekday': {
      const o = ORD_NAME[r.ord as number];
      const w = WD[r.weekday as number];
      return r.interval === 1 ? `monthly on ${o} ${w}` : `every ${r.interval} months on ${o} ${w}`;
    }
  }
}

// ---- human summary ----------------------------------------
export function summary(strOrObj: string | Rule | null): string {
  const r = typeof strOrObj === 'string' ? parse(strOrObj) : strOrObj;
  if (!r) return '';
  if (r.type === 'invalid') return 'invalid pattern';
  switch (r.type) {
    case 'daily':
      return r.interval === 1 ? 'Every day' : `Every ${r.interval} days`;
    case 'weekly': {
      const names = r.days && r.days.length ? r.days.map((i) => WD_FULL[i]).join(', ') : '—';
      if (r.interval === 1) return `Weekly on ${names}`;
      return r.days && r.days.length
        ? `Every ${r.interval} weeks on ${names}`
        : `Every ${r.interval} weeks`;
    }
    case 'monthly-day': {
      const d = r.day;
      if (!d) return `Every ${r.interval} months`;
      const suf = ordSuffix(d);
      return r.interval === 1
        ? `Monthly on the ${d}${suf}`
        : `Every ${r.interval} months on the ${d}${suf}`;
    }
    case 'monthly-weekday': {
      const ord = r.ord as number;
      const o = ord === -1 ? 'last' : ord + ordSuffix(ord);
      const w = WD_FULL[r.weekday as number];
      return r.interval === 1
        ? `Monthly on the ${o} ${w}`
        : `Every ${r.interval} months on the ${o} ${w}`;
    }
  }
}
export function ordSuffix(n: number): string {
  const s = ['th', 'st', 'nd', 'rd'];
  const v = n % 100;
  return s[(v - 20) % 10] || s[v] || s[0];
}

// compact one-line label for dense rows
export function compact(strOrObj: string | Rule | null): string {
  const r = typeof strOrObj === 'string' ? parse(strOrObj) : strOrObj;
  if (!r || r.type === 'invalid') return '';
  const A = ['Su', 'Mo', 'Tu', 'We', 'Th', 'Fr', 'Sa'];
  switch (r.type) {
    case 'daily':
      return r.interval === 1 ? 'daily' : `${r.interval}d`;
    case 'weekly': {
      const dd = r.days && r.days.length ? r.days.map((i) => A[i]).join('·') : '—';
      return r.interval === 1 ? dd : `${dd}/${r.interval}w`;
    }
    case 'monthly-day':
      if (!r.day) return `${r.interval}mo`;
      return r.interval === 1 ? `day ${r.day}` : `day ${r.day}/${r.interval}mo`;
    case 'monthly-weekday': {
      const ord = r.ord as number;
      const o = ord === -1 ? 'last' : ord + ordSuffix(ord);
      const w = A[r.weekday as number];
      return r.interval === 1 ? `${o} ${w}` : `${o} ${w}/${r.interval}mo`;
    }
  }
}

// ---- occurrence matching ----------------------------------
function nthWeekdayOfMonth(year: number, month: number, weekday: number, ord: number): Date | null {
  if (ord === -1) {
    const last = new Date(year, month + 1, 0);
    const back = (last.getDay() - weekday + 7) % 7;
    return new Date(year, month, last.getDate() - back);
  }
  const first = new Date(year, month, 1);
  const offset = (weekday - first.getDay() + 7) % 7;
  const day = 1 + offset + (ord - 1) * 7;
  const dim = new Date(year, month + 1, 0).getDate();
  if (day > dim) return null;
  return new Date(year, month, day);
}

export function matches(date: Date, r: Rule, anchor?: Date): boolean {
  date = startOfDay(date);
  anchor = anchor ? startOfDay(anchor) : date;
  if (date < anchor) return false;
  switch (r.type) {
    case 'daily': {
      const n = r.interval || 1;
      return daysBetween(anchor, date) % n === 0;
    }
    case 'weekly': {
      const n = r.interval || 1;
      const days = r.days && r.days.length ? r.days : [anchor.getDay()];
      if (!days.includes(date.getDay())) return false;
      // week phase: weeks since anchor's Sunday
      const aWeek = weekIndex(anchor);
      const dWeek = weekIndex(date);
      return (dWeek - aWeek) % n === 0;
    }
    case 'monthly-day': {
      const n = r.interval || 1;
      if (monthsBetween(anchor, date) % n !== 0) return false;
      const dim = new Date(date.getFullYear(), date.getMonth() + 1, 0).getDate();
      const target = r.day ? Math.min(r.day, dim) : Math.min(anchor.getDate(), dim);
      return date.getDate() === target;
    }
    case 'monthly-weekday': {
      const n = r.interval || 1;
      if (monthsBetween(anchor, date) % n !== 0) return false;
      const occ = nthWeekdayOfMonth(
        date.getFullYear(),
        date.getMonth(),
        r.weekday as number,
        r.ord as number,
      );
      return !!occ && sameDay(occ, date);
    }
  }
  return false;
}
function weekIndex(d: Date): number {
  return Math.floor(daysBetween(new Date(1970, 0, 4), d) / 7); // 1970-01-04 = Sunday
}
function monthsBetween(a: Date, b: Date): number {
  return (b.getFullYear() - a.getFullYear()) * 12 + (b.getMonth() - a.getMonth());
}

// ---- next N occurrences from a date (exclusive of `from` by default)
export function nextOccurrences(strOrObj: string | Rule | null, opts?: OccurrenceOpts): Date[] {
  opts = opts || {};
  const r = typeof strOrObj === 'string' ? parse(strOrObj) : strOrObj;
  if (!r || r.type === 'invalid') return [];
  const anchorD = opts.anchor
    ? typeof opts.anchor === 'string'
      ? parseYMD(opts.anchor)
      : opts.anchor
    : new Date();
  const fromD = opts.from
    ? typeof opts.from === 'string'
      ? parseYMD(opts.from)
      : opts.from
    : new Date();
  const count = opts.count || 3;
  const inclusive = !!opts.inclusive;
  const out: Date[] = [];
  let cur = startOfDay(fromD as Date);
  if (!inclusive) cur = addDays(cur, 1);
  let guard = 0;
  const cap = 366 * 6;
  while (out.length < count && guard < cap) {
    if (matches(cur, r, anchorD as Date)) out.push(new Date(cur));
    cur = addDays(cur, 1);
    guard++;
  }
  return out;
}

// next single occurrence strictly after `from`
export function next(
  strOrObj: string | Rule | null,
  from?: string | Date,
  anchor?: string | Date,
): Date | null {
  const r = nextOccurrences(strOrObj, { from, anchor: anchor || from, count: 1 });
  return r[0] || null;
}

export const Rec = {
  parse,
  stringify,
  summary,
  compact,
  matches,
  nextOccurrences,
  next,
  ymd,
  parseYMD,
  addDays,
  startOfDay,
  daysBetween,
  ordSuffix,
  WD,
  WD_FULL,
  ORD_NAME,
};
export default Rec;

// Shared route guard: resolve access and reply 404 (invisible) / 403 (read-only)
// when the action isn't permitted. Returns true if it replied (caller should stop).

import type { FastifyInstance, FastifyReply, FastifyRequest } from 'fastify';
import { type Action, type ResourceType, accessLevel, denyStatus } from '../authz.js';

export async function denyAccess(
  app: FastifyInstance,
  request: FastifyRequest,
  reply: FastifyReply,
  type: ResourceType,
  id: string,
  action: Action,
): Promise<boolean> {
  const status = denyStatus(await accessLevel(app.db, request.user!, type, id), action);
  if (status) {
    reply.code(status).send({ error: status === 404 ? 'not found' : 'forbidden' });
    return true;
  }
  return false;
}

export const ifMatchOf = (request: FastifyRequest): string | undefined => {
  const h = request.headers['if-match'];
  return typeof h === 'string' ? h : undefined;
};

// authz.ts — the single access-control chokepoint. The unit of sharing is the
// project; a task inherits its project's access. Labels/saved-queries are
// owner-only in D1 (not shareable yet). Grants target a project for a principal
// (a user, or a group the user belongs to); roles: viewer=read, editor=read+write,
// owner=all. Default (no grants) = owner-only.

import type { DB } from './db.js';

export type ResourceType = 'task' | 'project' | 'label' | 'saved_query' | 'event' | 'note';
export type Action = 'read' | 'write';
export type AccessLevel = 'none' | 'read' | 'write';

interface UserRef {
  id: string;
}

function roleLevel(role: string): AccessLevel {
  if (role === 'owner' || role === 'editor') return 'write';
  if (role === 'viewer') return 'read';
  return 'none';
}
const best = (a: AccessLevel, b: AccessLevel): AccessLevel =>
  a === 'write' || b === 'write' ? 'write' : a === 'read' || b === 'read' ? 'read' : 'none';

// Best access a user has on a resource ('none' | 'read' | 'write').
export async function accessLevel(
  db: DB,
  user: UserRef,
  type: ResourceType,
  id: string,
): Promise<AccessLevel> {
  if (type === 'task') {
    const t = await db
      .selectFrom('tasks')
      .select(['owner_id', 'project_id'])
      .where('id', '=', id)
      .executeTakeFirst();
    if (!t) return 'none';
    if (t.owner_id === user.id) return 'write';
    return t.project_id ? accessLevel(db, user, 'project', t.project_id) : 'none';
  }
  if (type === 'project') {
    const p = await db
      .selectFrom('projects')
      .select('owner_id')
      .where('id', '=', id)
      .executeTakeFirst();
    if (!p) return 'none';
    if (p.owner_id === user.id) return 'write';
    return projectGrantLevel(db, user.id, id);
  }
  // event | label | saved_query — owner-only in D1/D2
  if (type === 'event') {
    const row = await db
      .selectFrom('events')
      .select('owner_id')
      .where('id', '=', id)
      .executeTakeFirst();
    return row && row.owner_id === user.id ? 'write' : 'none';
  }
  if (type === 'note') {
    const row = await db
      .selectFrom('notes')
      .select(['owner_id', 'tombstoned'])
      .where('id', '=', id)
      .executeTakeFirst();
    return row && !row.tombstoned && row.owner_id === user.id ? 'write' : 'none';
  }
  if (type === 'label') {
    const row = await db
      .selectFrom('labels')
      .select('owner_id')
      .where('id', '=', id)
      .executeTakeFirst();
    return row && row.owner_id === user.id ? 'write' : 'none';
  }
  const row = await db
    .selectFrom('saved_queries')
    .select('owner_id')
    .where('id', '=', id)
    .executeTakeFirst();
  return row && row.owner_id === user.id ? 'write' : 'none';
}

async function projectGrantLevel(db: DB, userId: string, projectId: string): Promise<AccessLevel> {
  const groups = await db
    .selectFrom('group_members')
    .select('group_id')
    .where('user_id', '=', userId)
    .execute();
  const groupIds = groups.map((g) => g.group_id);

  const rows = await db
    .selectFrom('grants')
    .select('role')
    .where('resource_type', '=', 'project')
    .where('resource_id', '=', projectId)
    .where((eb) =>
      eb.or([
        eb.and([eb('principal_type', '=', 'user'), eb('principal_id', '=', userId)]),
        ...(groupIds.length
          ? [eb.and([eb('principal_type', '=', 'group'), eb('principal_id', 'in', groupIds)])]
          : []),
      ]),
    )
    .execute();

  return rows.reduce<AccessLevel>((lvl, r) => best(lvl, roleLevel(r.role)), 'none');
}

export async function canAccess(
  db: DB,
  user: UserRef,
  type: ResourceType,
  id: string,
  action: Action,
): Promise<boolean> {
  const lvl = await accessLevel(db, user, type, id);
  return lvl === 'write' || (lvl === 'read' && action === 'read');
}

// For routes: 404 if invisible, 403 if visible-but-not-writable, else null (allowed).
export function denyStatus(level: AccessLevel, action: Action): 404 | 403 | null {
  if (level === 'none') return 404;
  if (action === 'write' && level !== 'write') return 403;
  return null;
}

// routes/labels.ts — label CRUD + merge. No updated_at → writes are unconditional.

import type { FastifyInstance } from 'fastify';
import { LabelCreateSchema, LabelMergeSchema, LabelUpdateSchema } from '../schemas.js';
import {
  createLabel,
  deleteLabel,
  getLabel,
  mergeLabels,
  updateLabel,
} from '../services/labels.js';
import { denyAccess } from './_access.js';

export default async function labelRoutes(app: FastifyInstance): Promise<void> {
  app.post(
    '/api/labels',
    { preHandler: app.requireWrite, schema: { body: LabelCreateSchema } },
    async (request, reply) => {
      const label = await createLabel(
        app.db,
        request.user!.id,
        request.body as { name: string; pinned?: boolean },
      );
      return reply.code(201).send(label);
    },
  );

  // static route before the param route so '/api/labels/merge' isn't read as :id
  app.post(
    '/api/labels/merge',
    { preHandler: app.requireWrite, schema: { body: LabelMergeSchema } },
    async (request, reply) => {
      const { from, to } = request.body as { from: string; to: string };
      if (await denyAccess(app, request, reply, 'label', from, 'write')) return;
      if (await denyAccess(app, request, reply, 'label', to, 'write')) return;
      const ok = await mergeLabels(app.db, request.user!.id, from, to);
      if (!ok) return reply.code(400).send({ error: 'cannot merge those labels' });
      return { ok: true };
    },
  );

  app.get('/api/labels/:id', { preHandler: app.authenticate }, async (request, reply) => {
    const { id } = request.params as { id: string };
    if (await denyAccess(app, request, reply, 'label', id, 'read')) return;
    return getLabel(app.db, id);
  });

  app.put(
    '/api/labels/:id',
    { preHandler: app.requireWrite, schema: { body: LabelUpdateSchema } },
    async (request, reply) => {
      const { id } = request.params as { id: string };
      if (await denyAccess(app, request, reply, 'label', id, 'write')) return;
      return updateLabel(app.db, id, request.body as { name?: string; pinned?: boolean });
    },
  );

  app.delete('/api/labels/:id', { preHandler: app.requireWrite }, async (request, reply) => {
    const { id } = request.params as { id: string };
    if (await denyAccess(app, request, reply, 'label', id, 'write')) return;
    await deleteLabel(app.db, id);
    return reply.code(204).send();
  });
}

// services/labels.ts — label CRUD (no updated_at → unconditional writes),
// delete (strip from tasks, keep tasks), and merge (dedupe). Owner-only in D1.

import type { Updateable } from 'kysely';
import type { DB, LabelsTable } from '../db.js';
import { newId } from '../ids.js';
import { rowToLabel } from '../schemas.js';

export async function getLabel(db: DB, id: string) {
  const row = await db.selectFrom('labels').selectAll().where('id', '=', id).executeTakeFirst();
  return row ? rowToLabel(row) : null;
}

export async function createLabel(
  db: DB,
  owner: string,
  input: { id?: string; name: string; pinned?: boolean },
) {
  const id = input.id ?? newId();
  await db
    .insertInto('labels')
    .values({ id, owner_id: owner, name: input.name, pinned: input.pinned ? 1 : 0 })
    .execute();
  return (await getLabel(db, id))!;
}

export async function updateLabel(db: DB, id: string, patch: { name?: string; pinned?: boolean }) {
  const set: Updateable<LabelsTable> = {};
  if (patch.name !== undefined) set.name = patch.name;
  if (patch.pinned !== undefined) set.pinned = patch.pinned ? 1 : 0;
  if (Object.keys(set).length)
    await db.updateTable('labels').set(set).where('id', '=', id).execute();
  return getLabel(db, id);
}

// Strip the label from every task (tasks stay), then drop the label.
export async function deleteLabel(db: DB, id: string): Promise<void> {
  await db.transaction().execute(async (trx) => {
    await trx.deleteFrom('task_labels').where('label_id', '=', id).execute();
    await trx.deleteFrom('labels').where('id', '=', id).execute();
  });
}

// Fold `fromId` into `toId`: re-point task_labels (deduped), then drop the source.
export async function mergeLabels(
  db: DB,
  owner: string,
  fromId: string,
  toId: string,
): Promise<boolean> {
  if (fromId === toId) return false;
  const both = await db
    .selectFrom('labels')
    .select('id')
    .where('owner_id', '=', owner)
    .where('id', 'in', [fromId, toId])
    .execute();
  if (both.length !== 2) return false; // both must belong to the owner
  await db.transaction().execute(async (trx) => {
    await trx
      .insertInto('task_labels')
      .columns(['task_id', 'label_id'])
      .expression((eb) =>
        eb
          .selectFrom('task_labels')
          .select(['task_id', eb.val(toId).as('label_id')])
          .where('label_id', '=', fromId),
      )
      .onConflict((oc) => oc.doNothing())
      .execute();
    await trx.deleteFrom('task_labels').where('label_id', '=', fromId).execute();
    await trx.deleteFrom('labels').where('id', '=', fromId).execute();
  });
  return true;
}

// routes/links.ts — the generic entity-link graph (D2 §3). Create/list/delete
// undirected links between any two linkable entities. Access is enforced per
// endpoint via the shared denyAccess guard; rel validity is enforced by the
// service (canonical alphabetical pair-name). Owner-scoped.

import type { FastifyInstance } from 'fastify';
import { LinkCreateSchema, LinkListSchema, LinkQuerySchema } from '../schemas.js';
import {
  InvalidLink,
  type LinkType,
  createLink,
  deleteLink,
  getLinksFor,
} from '../services/links.js';
import { denyAccess } from './_access.js';

export default async function linkRoutes(app: FastifyInstance): Promise<void> {
  app.post(
    '/api/links',
    { preHandler: app.requireWrite, schema: { body: LinkCreateSchema } },
    async (request, reply) => {
      const { aType, aId, bType, bId, data } = request.body as {
        aType: LinkType;
        aId: string;
        bType: LinkType;
        bId: string;
        data?: unknown;
      };
      // both endpoints must be visible to the caller (404 invisible / 403 read-only)
      if (await denyAccess(app, request, reply, aType, aId, 'read')) return;
      if (await denyAccess(app, request, reply, bType, bId, 'read')) return;
      try {
        const link = await createLink(
          app.db,
          request.user!.id,
          { type: aType, id: aId },
          { type: bType, id: bId },
          data,
        );
        return reply.code(201).send(link);
      } catch (err) {
        if (err instanceof InvalidLink) return reply.code(400).send({ error: err.message });
        throw err;
      }
    },
  );

  app.get(
    '/api/links',
    {
      preHandler: app.authenticate,
      schema: { querystring: LinkQuerySchema, response: { 200: LinkListSchema } },
    },
    async (request, reply) => {
      const { type, id } = request.query as { type: LinkType; id: string };
      if (await denyAccess(app, request, reply, type, id, 'read')) return;
      return getLinksFor(app.db, request.user!.id, type, id);
    },
  );

  app.delete('/api/links/:id', { preHandler: app.requireWrite }, async (request, reply) => {
    const { id } = request.params as { id: string };
    await deleteLink(app.db, request.user!.id, id);
    return reply.code(204).send();
  });
}

// services/links.ts — the generic entity-link graph (D2 §3). Rels are MECHANICAL
// pair-names: the rel is the alphabetical concept-pair (e.g. 'event-task'), one
// undirected edge per pair, stored CANONICALLY (alphabetically-first type is t1)
// so there's no (A,B)/(B,A) duplication. A tiny type registry resolves (type,id)
// → a display ref with scoped access. Reconcile-on-read: links whose far endpoint
// is archived/missing are hidden (archive is soft + reversible, so we don't delete
// the edge — getLinksFor just skips it, and it returns on unarchive).

import { accessLevel } from '../authz.js';
import type { DB } from '../db.js';
import { newId } from '../ids.js';

export type LinkType = 'event' | 'task' | 'note';
export interface LinkEndpoint {
  type: LinkType;
  id: string;
}
export interface EntityRef {
  type: LinkType;
  id: string;
  title: string;
}
export interface LinkResolved {
  id: string;
  rel: string;
  other: EntityRef;
  createdAt: string;
  source: 'app' | 'content'; // app-asserted (unlinkable) vs derived from a note's [[wikilink]]
}

// The "tiny type registry" (§3): which table backs each linkable concept. Adding
// `note` in 2c is one more entry here + its rels below. Both backing tables carry
// `title` + `archived`, which is all link resolution needs.
export const LINKABLE_TYPES: readonly LinkType[] = ['event', 'task', 'note'];
// Finite, mechanical rel set (alphabetical pair-names) for APP-asserted links.
// note-note is intentionally absent — same-type note↔note edges are content-only
// (parsed from [[wikilinks]] into `note_links`), never created through the API.
const ALLOWED_RELS = new Set(['event-task', 'event-note', 'note-task']);

// Thrown when a pair has no valid rel (same-type, or a pair outside the taxonomy).
export class InvalidLink extends Error {}

// Canonical ordering: the alphabetically-first type is t1; rel = `${t1}-${t2}`.
function canonicalize(
  a: LinkEndpoint,
  b: LinkEndpoint,
): { t1: LinkEndpoint; t2: LinkEndpoint; rel: string } {
  const [t1, t2] = a.type <= b.type ? [a, b] : [b, a];
  const rel = `${t1.type}-${t2.type}`;
  if (!ALLOWED_RELS.has(rel)) throw new InvalidLink(`unsupported link: ${rel}`);
  return { t1, t2, rel };
}

// Backing-row fetch (title + archived), branched so Kysely stays fully typed.
function fetchRow(
  db: DB,
  type: LinkType,
  id: string,
): Promise<{ title: string; archived: number } | undefined> {
  if (type === 'event')
    return db
      .selectFrom('events')
      .select(['title', 'archived'])
      .where('id', '=', id)
      .executeTakeFirst();
  if (type === 'note')
    return db
      .selectFrom('notes')
      .select(['title', 'tombstoned as archived']) // tombstoned is the note hide-flag
      .where('id', '=', id)
      .executeTakeFirst();
  return db
    .selectFrom('tasks')
    .select(['title', 'archived'])
    .where('id', '=', id)
    .executeTakeFirst();
}

// Access-checked, archive-hiding resolution (used by getLinksFor's reconcile-on-read).
async function resolveEntity(
  db: DB,
  owner: string,
  type: LinkType,
  id: string,
): Promise<EntityRef | null> {
  if ((await accessLevel(db, { id: owner }, type, id)) === 'none') return null;
  const row = await fetchRow(db, type, id);
  if (!row || row.archived) return null;
  return { type, id, title: row.title };
}

// Create (or no-op if it already exists) a link between two entities. Access to
// both endpoints is enforced at the route; this canonicalizes + inserts idempotently
// and returns the edge resolved from `a`'s point of view (`other` = b).
export async function createLink(
  db: DB,
  owner: string,
  a: LinkEndpoint,
  b: LinkEndpoint,
  data?: unknown,
): Promise<LinkResolved> {
  const { t1, t2, rel } = canonicalize(a, b);
  const now = new Date().toISOString();
  await db
    .insertInto('links')
    .values({
      id: newId(),
      owner_id: owner,
      t1_type: t1.type,
      t1_id: t1.id,
      t2_type: t2.type,
      t2_id: t2.id,
      rel,
      data: data === undefined ? null : JSON.stringify(data),
      created_at: now,
    })
    .onConflict((oc) =>
      oc.columns(['owner_id', 't1_type', 't1_id', 't2_type', 't2_id']).doNothing(),
    )
    .execute();

  // re-read the canonical row (existing or just-inserted) for its id + created_at
  const row = await db
    .selectFrom('links')
    .selectAll()
    .where('owner_id', '=', owner)
    .where('t1_type', '=', t1.type)
    .where('t1_id', '=', t1.id)
    .where('t2_type', '=', t2.type)
    .where('t2_id', '=', t2.id)
    .executeTakeFirstOrThrow();

  const bRow = await fetchRow(db, b.type, b.id);
  const other: EntityRef = { type: b.type, id: b.id, title: bRow?.title ?? '' };
  return { id: row.id, rel: row.rel, other, createdAt: row.created_at, source: 'app' };
}

export async function deleteLink(db: DB, owner: string, id: string): Promise<void> {
  await db.deleteFrom('links').where('id', '=', id).where('owner_id', '=', owner).execute();
}

// Every link touching (type,id), each resolved to its far side. Merges TWO
// sources: 2b's app-asserted `links` (undirected, canonical) + 2c's file-derived
// `note_links` (directional content edges parsed from markdown). Skips edges whose
// far endpoint is archived/tombstoned/missing (reconcile-on-read), and dedups by
// the far endpoint so a pair linked both ways shows once.
export async function getLinksFor(
  db: DB,
  owner: string,
  type: LinkType,
  id: string,
): Promise<LinkResolved[]> {
  // (other-type, other-id, edge-id, rel, created_at, source) candidates from both sources
  const candidates: {
    otherType: LinkType;
    otherId: string;
    id: string;
    rel: string;
    createdAt: string;
    source: 'app' | 'content';
  }[] = [];

  // app links — the entity is t1 or t2; the far side is the other endpoint
  const appRows = await db
    .selectFrom('links')
    .selectAll()
    .where('owner_id', '=', owner)
    .where((eb) =>
      eb.or([
        eb.and([eb('t1_type', '=', type), eb('t1_id', '=', id)]),
        eb.and([eb('t2_type', '=', type), eb('t2_id', '=', id)]),
      ]),
    )
    .execute();
  for (const row of appRows) {
    const isT1 = row.t1_type === type && row.t1_id === id;
    candidates.push({
      otherType: (isT1 ? row.t2_type : row.t1_type) as LinkType,
      otherId: isT1 ? row.t2_id : row.t1_id,
      id: row.id,
      rel: row.rel,
      createdAt: row.created_at,
      source: 'app',
    });
  }

  // content links — files that point AT this entity (far side = the origin note)…
  const inbound = await db
    .selectFrom('note_links')
    .selectAll()
    .where('owner_id', '=', owner)
    .where('target_type', '=', type)
    .where('target_id', '=', id)
    .execute();
  for (const row of inbound) {
    candidates.push({
      otherType: 'note',
      otherId: row.origin_note_id,
      id: row.id,
      rel: row.rel,
      createdAt: row.created_at,
      source: 'content',
    });
  }
  // …and, when querying a note, the things ITS file points at (far side = target)
  if (type === 'note') {
    const outbound = await db
      .selectFrom('note_links')
      .selectAll()
      .where('owner_id', '=', owner)
      .where('origin_note_id', '=', id)
      .execute();
    for (const row of outbound) {
      candidates.push({
        otherType: row.target_type as LinkType,
        otherId: row.target_id,
        id: row.id,
        rel: row.rel,
        createdAt: row.created_at,
        source: 'content',
      });
    }
  }

  const seen = new Set<string>();
  const out: LinkResolved[] = [];
  for (const c of candidates) {
    const key = `${c.otherType}:${c.otherId}`;
    if (seen.has(key)) continue;
    const other = await resolveEntity(db, owner, c.otherType, c.otherId);
    if (!other) continue;
    seen.add(key);
    out.push({ id: c.id, rel: c.rel, other, createdAt: c.createdAt, source: c.source });
  }
  out.sort((a, b) => a.createdAt.localeCompare(b.createdAt));
  return out;
}

// Bulk-remove an entity's edges. Reserved for hard-delete / 2c note tombstones;
// intentionally NOT wired in 2b — archive is soft + reversible, so getLinksFor
// hides archived endpoints and the edges survive an unarchive.
export async function deleteLinksFor(
  db: DB,
  owner: string,
  type: LinkType,
  id: string,
): Promise<void> {
  await db
    .deleteFrom('links')
    .where('owner_id', '=', owner)
    .where((eb) =>
      eb.or([
        eb.and([eb('t1_type', '=', type), eb('t1_id', '=', id)]),
        eb.and([eb('t2_type', '=', type), eb('t2_id', '=', id)]),
      ]),
    )
    .execute();
}

// routes/notes.ts — the note domain (D2 §4). Notes are file-backed and owner-only.
// Mutations own the .md file (write then scan); reads pull the body from disk.
// `sync` (increment 2) drives a vault scan for externally-edited files.

import type { FastifyInstance } from 'fastify';
import {
  NoteCreateSchema,
  NoteListSchema,
  NoteSchema,
  NoteSearchQuerySchema,
  NoteSearchResponseSchema,
  NoteSyncQuerySchema,
  NoteSyncResponseSchema,
  NoteUpdateSchema,
} from '../schemas.js';
import {
  createNote,
  deleteNote,
  getNote,
  listNotes,
  scanVault,
  searchNotes,
  updateNote,
} from '../services/notes.js';
import { denyAccess } from './_access.js';

export default async function noteRoutes(app: FastifyInstance): Promise<void> {
  app.post(
    '/api/notes',
    {
      preHandler: app.requireWrite,
      schema: { body: NoteCreateSchema, response: { 201: NoteSchema } },
    },
    async (request, reply) => {
      const note = await createNote(
        app.db,
        request.user!.id,
        request.body as Parameters<typeof createNote>[2],
      );
      return reply.code(201).send(note);
    },
  );

  app.get(
    '/api/notes',
    { preHandler: app.authenticate, schema: { response: { 200: NoteListSchema } } },
    async (request) => listNotes(app.db, request.user!.id),
  );

  // reconcile the DB shadow with the vault (external nvim/Obsidian edits): the
  // sync button / window-focus / nightly trigger. incremental (default) | full.
  app.post(
    '/api/notes/sync',
    {
      preHandler: app.requireWrite,
      schema: { querystring: NoteSyncQuerySchema, response: { 200: NoteSyncResponseSchema } },
    },
    async (request) => {
      const { mode } = request.query as { mode?: 'incremental' | 'full' };
      return scanVault(app.db, request.user!.id, mode ?? 'incremental');
    },
  );

  // static route — registered before :id, and Fastify's router prefers it anyway
  app.get(
    '/api/notes/search',
    {
      preHandler: app.authenticate,
      schema: { querystring: NoteSearchQuerySchema, response: { 200: NoteSearchResponseSchema } },
    },
    async (request) => searchNotes(app.db, request.user!.id, (request.query as { q: string }).q),
  );

  app.get('/api/notes/:id', { preHandler: app.authenticate }, async (request, reply) => {
    const { id } = request.params as { id: string };
    if (await denyAccess(app, request, reply, 'note', id, 'read')) return;
    const note = await getNote(app.db, request.user!.id, id);
    if (!note) return reply.code(404).send({ error: 'not found' });
    return reply.send(note);
  });

  app.put(
    '/api/notes/:id',
    { preHandler: app.requireWrite, schema: { body: NoteUpdateSchema } },
    async (request, reply) => {
      const { id } = request.params as { id: string };
      if (await denyAccess(app, request, reply, 'note', id, 'write')) return;
      const note = await updateNote(
        app.db,
        request.user!.id,
        id,
        request.body as Parameters<typeof updateNote>[3],
      );
      if (!note) return reply.code(404).send({ error: 'not found' });
      return reply.send(note);
    },
  );

  app.delete('/api/notes/:id', { preHandler: app.requireWrite }, async (request, reply) => {
    const { id } = request.params as { id: string };
    if (await denyAccess(app, request, reply, 'note', id, 'write')) return;
    await deleteNote(app.db, request.user!.id, id);
    return reply.code(204).send();
  });
}

// services/notes.ts — the note domain (D2 §4). Note CONTENT is the .md file on
// disk (the vault); these helpers keep the DB shadow (notes row + FTS index, and
// — wired in increment 3 — the file-derived link edges) in step. `scanFile` is the
// atom: read → parse → (writeback id) → upsert row → refresh FTS → reconcile links.
// The CRUD wrappers own the file (write it, then scan); `scanVault` (increment 2)
// drives `scanFile` over the whole vault for external edits.

import fs from 'node:fs';
import path from 'node:path';
import { sql } from 'kysely';
import type { DB } from '../db.js';
import { newId } from '../ids.js';
import { type NoteJson, rowToNote } from '../schemas.js';
import { abs, vaultBase, vaultRoot } from '../vault.js';
import {
  type ExtractedLinks,
  extractLinks,
  injectFrontmatterId,
  parseNote,
  serializeNote,
} from './markdown.js';

// ---- FTS keyword index (derived, one row per note) -------------------------
async function refreshFts(
  db: DB,
  noteId: string,
  owner: string,
  title: string,
  body: string,
): Promise<void> {
  await sql`DELETE FROM notes_fts WHERE note_id = ${noteId}`.execute(db);
  await sql`INSERT INTO notes_fts (note_id, owner_id, title, body)
            VALUES (${noteId}, ${owner}, ${title}, ${body})`.execute(db);
}

// user text → a safe FTS5 MATCH expression: word-ish tokens, prefix-matched, AND-ed
function ftsQuery(q: string): string {
  return q
    .split(/\s+/)
    .map((t) => t.replace(/[^\p{L}\p{N}_]/gu, ''))
    .filter(Boolean)
    .map((t) => `${t}*`)
    .join(' ');
}

// ---- the scan atom ---------------------------------------------------------
// Index one vault file by its relative path. Returns the note, or null if the
// file is missing (scanVault turns that into a tombstone). Assigns + writes back
// a frontmatter id when the file lacks one.
export async function scanFile(db: DB, owner: string, relPath: string): Promise<NoteJson | null> {
  const absPath = abs(owner, relPath);
  let raw: string;
  try {
    raw = fs.readFileSync(absPath, 'utf8');
  } catch {
    return null;
  }
  const parsed = parseNote(raw);
  let id = parsed.id;
  if (!id) {
    id = newId();
    fs.writeFileSync(absPath, injectFrontmatterId(raw, id)); // gentle writeback
  }
  const title = path.basename(relPath, '.md'); // the filename IS the title (Obsidian model)
  const mtime = fs.statSync(absPath).mtime.toISOString();
  const now = new Date().toISOString();
  const fmJson = Object.keys(parsed.frontmatter).length ? JSON.stringify(parsed.frontmatter) : null;

  // owner-scoped lookup: a foreign note with the same frontmatter id is NOT ours to update
  const existing = await db
    .selectFrom('notes')
    .select('id')
    .where('id', '=', id)
    .where('owner_id', '=', owner)
    .executeTakeFirst();
  if (existing) {
    await db
      .updateTable('notes')
      .set({ path: relPath, title, mtime, frontmatter: fmJson, tombstoned: 0, updated_at: now })
      .where('id', '=', id)
      .where('owner_id', '=', owner)
      .execute();
  } else {
    await db
      .insertInto('notes')
      .values({
        id,
        owner_id: owner,
        path: relPath,
        title,
        mtime,
        frontmatter: fmJson,
        tombstoned: 0,
        created_at: now,
        updated_at: now,
      })
      .execute();
  }
  await refreshFts(db, id, owner, title, parsed.body);
  await reconcileFileLinks(db, owner, id, extractLinks(parsed.body));
  return getNote(db, owner, id);
}

// ---- file-derived links (content edges → note_links) -----------------------
// Resolve an Obsidian-style [[Name]] to a note id (by title or filename); null if
// missing/dangling (it re-resolves on a later scan once the target exists).
async function resolveNoteName(db: DB, owner: string, name: string): Promise<string | null> {
  const rows = await db
    .selectFrom('notes')
    .select(['id', 'path', 'title'])
    .where('owner_id', '=', owner)
    .where('tombstoned', '=', 0)
    .execute();
  const lc = name.toLowerCase();
  const hit = rows.find(
    (r) => r.title.toLowerCase() === lc || path.basename(r.path, '.md').toLowerCase() === lc,
  );
  return hit ? hit.id : null;
}

const relFor = (target: 'task' | 'event' | 'note'): string => ['note', target].sort().join('-');

async function targetExists(
  db: DB,
  owner: string,
  type: 'task' | 'event',
  id: string,
): Promise<boolean> {
  const t = type === 'task' ? 'tasks' : 'events';
  const row = await db
    .selectFrom(t)
    .select('id')
    .where('id', '=', id)
    .where('owner_id', '=', owner)
    .where('archived', '=', 0)
    .executeTakeFirst();
  return !!row;
}

// Replace a note's content edges to exactly match what's written in its file now.
// Only materialize edges to existing, owned targets (dangling [[task:bad]] / unknown
// names are skipped). getLinksFor surfaces these alongside the app-asserted links.
export async function reconcileFileLinks(
  db: DB,
  owner: string,
  noteId: string,
  parsed: ExtractedLinks,
): Promise<void> {
  await db
    .deleteFrom('note_links')
    .where('owner_id', '=', owner)
    .where('origin_note_id', '=', noteId)
    .execute();

  const targets: { target_type: 'task' | 'event' | 'note'; target_id: string }[] = [];
  for (const id of parsed.tasks) {
    if (await targetExists(db, owner, 'task', id))
      targets.push({ target_type: 'task', target_id: id });
  }
  for (const id of parsed.events) {
    if (await targetExists(db, owner, 'event', id))
      targets.push({ target_type: 'event', target_id: id });
  }
  for (const name of parsed.notes) {
    const id = await resolveNoteName(db, owner, name);
    if (id && id !== noteId) targets.push({ target_type: 'note', target_id: id }); // no self-links
  }

  const now = new Date().toISOString();
  for (const t of targets) {
    await db
      .insertInto('note_links')
      .values({
        id: newId(),
        owner_id: owner,
        origin_note_id: noteId,
        target_type: t.target_type,
        target_id: t.target_id,
        rel: relFor(t.target_type),
        created_at: now,
      })
      .execute();
  }
}

// ---- scanVault: drive scanFile over the whole vault ------------------------
// Enumerate *.md, (re)index changed files, then detect deletions → tombstone.
// `incremental` skips files whose mtime matches the row; `full` rescans all.
// Triggers (per §4): sync button / window-focus / nightly → incremental.
function walkMd(root: string): string[] {
  const out: string[] = [];
  const walk = (dir: string) => {
    for (const ent of fs.readdirSync(dir, { withFileTypes: true })) {
      if (ent.name.startsWith('.')) continue; // skip dotfiles/dirs (e.g. .obsidian)
      if (ent.isSymbolicLink()) continue; // don't follow symlinks out of the vault
      const full = path.join(dir, ent.name);
      if (ent.isDirectory()) walk(full);
      else if (ent.isFile() && ent.name.endsWith('.md')) out.push(path.relative(root, full));
    }
  };
  walk(root);
  return out;
}

export interface ScanSummary {
  scanned: number;
  updated: number;
  tombstoned: number;
}
export async function scanVault(
  db: DB,
  owner: string,
  mode: 'incremental' | 'full' = 'incremental',
): Promise<ScanSummary> {
  const root = vaultRoot(owner);
  const files = walkMd(root);
  const live = await db
    .selectFrom('notes')
    .select(['path', 'mtime'])
    .where('owner_id', '=', owner)
    .where('tombstoned', '=', 0)
    .execute();
  const byPath = new Map(live.map((r) => [r.path, r.mtime]));

  let updated = 0;
  for (const relPath of files) {
    if (mode === 'incremental') {
      const knownMtime = byPath.get(relPath);
      if (knownMtime && fs.statSync(abs(owner, relPath)).mtime.toISOString() === knownMtime)
        continue;
    }
    await scanFile(db, owner, relPath); // resolves moves (upsert by frontmatter id)
    updated++;
  }

  // deletion detection — runs AFTER scanning so a move (path rewrite) isn't misread
  let tombstoned = 0;
  const fresh = await db
    .selectFrom('notes')
    .select(['id', 'path'])
    .where('owner_id', '=', owner)
    .where('tombstoned', '=', 0)
    .execute();
  for (const r of fresh) {
    if (fs.existsSync(abs(owner, r.path))) continue;
    await db
      .updateTable('notes')
      .set({ tombstoned: 1, updated_at: new Date().toISOString() })
      .where('id', '=', r.id)
      .execute();
    await sql`DELETE FROM notes_fts WHERE note_id = ${r.id}`.execute(db);
    await db
      .deleteFrom('note_links')
      .where('owner_id', '=', owner)
      .where('origin_note_id', '=', r.id)
      .execute();
    tombstoned++;
  }
  return { scanned: files.length, updated, tombstoned };
}

// ---- file-owning CRUD ------------------------------------------------------
// The title IS the filename (Obsidian model). Strip characters illegal in a
// filename or in a [[wikilink]] target so names stay portable + linkable; the
// hidden frontmatter id carries identity, so renames never break links.
function sanitizeName(title: string): string {
  return (
    title
      .replace(/[\\/:*?"<>|#^[\]]/g, '') // filesystem- + wikilink-illegal characters
      .replace(/\s+/g, ' ')
      .replace(/^[.\s]+|[.\s]+$/g, '') // no leading/trailing dots or spaces
      .slice(0, 120) || 'untitled'
  );
}
// First free `Name.md`, `Name 2.md`, … (Obsidian-style). `keep` is the note's own
// current path, which never counts as a collision (a no-op rename stays put).
function uniqueFile(owner: string, name: string, keep?: string): string {
  for (let n = 1; ; n++) {
    const candidate = n === 1 ? `${name}.md` : `${name} ${n}.md`;
    if (candidate === keep || !fs.existsSync(abs(owner, candidate))) return candidate;
  }
}

export async function createNote(
  db: DB,
  owner: string,
  input: { title: string; body?: string },
): Promise<NoteJson> {
  vaultRoot(owner); // ensure the owner's dir exists
  const id = newId();
  const relPath = uniqueFile(owner, sanitizeName(input.title));
  fs.writeFileSync(abs(owner, relPath), serializeNote({ id, body: input.body ?? '' }));
  return (await scanFile(db, owner, relPath))!;
}

// Editing the title renames the file on disk (identity is the frontmatter id, so
// links survive). Body is rewritten in place; extra frontmatter is preserved.
export async function updateNote(
  db: DB,
  owner: string,
  id: string,
  patch: { title?: string; body?: string },
): Promise<NoteJson | null> {
  const row = await db
    .selectFrom('notes')
    .selectAll()
    .where('id', '=', id)
    .where('owner_id', '=', owner)
    .executeTakeFirst();
  if (!row || row.tombstoned) return null;
  const oldRel = row.path;
  const parsed = parseNote(fs.readFileSync(abs(owner, oldRel), 'utf8'));
  const body = patch.body ?? parsed.body;
  const wantName =
    patch.title !== undefined ? sanitizeName(patch.title) : path.basename(oldRel, '.md');
  const newRel = uniqueFile(owner, wantName, oldRel);
  const content = serializeNote({ id, body, frontmatter: parsed.frontmatter });
  // Write content in place, then atomically rename — so a crash never leaves two
  // files sharing one frontmatter id (the old write-new + unlink-old window).
  fs.writeFileSync(abs(owner, oldRel), content);
  if (newRel !== oldRel) fs.renameSync(abs(owner, oldRel), abs(owner, newRel));
  return scanFile(db, owner, newRel);
}

export async function deleteNote(db: DB, owner: string, id: string): Promise<boolean> {
  const row = await db
    .selectFrom('notes')
    .selectAll()
    .where('id', '=', id)
    .where('owner_id', '=', owner)
    .executeTakeFirst();
  if (!row) return false;
  try {
    fs.unlinkSync(abs(owner, row.path));
  } catch {
    /* already gone — tombstone anyway */
  }
  await db
    .updateTable('notes')
    .set({ tombstoned: 1, updated_at: new Date().toISOString() })
    .where('id', '=', id)
    .execute();
  await sql`DELETE FROM notes_fts WHERE note_id = ${id}`.execute(db);
  await db
    .deleteFrom('note_links')
    .where('owner_id', '=', owner)
    .where('origin_note_id', '=', id)
    .execute();
  return true;
}

// One-time, idempotent migration to the per-owner vault layout: move any legacy
// flat file (vault/<path>) into its owner's subdir (vault/<owner_id>/<path>), based
// on the DB rows. Re-runs are no-ops once files live under their owner. Run at boot.
export async function migrateVaultLayout(db: DB): Promise<number> {
  const base = vaultBase();
  const rows = await db
    .selectFrom('notes')
    .select(['owner_id', 'path'])
    .where('tombstoned', '=', 0)
    .execute();
  let moved = 0;
  for (const r of rows) {
    const flat = path.join(base, r.path); // legacy location
    const dest = path.join(base, r.owner_id, r.path);
    if (flat === dest) continue;
    try {
      if (fs.existsSync(flat) && !fs.existsSync(dest)) {
        fs.mkdirSync(path.dirname(dest), { recursive: true });
        fs.renameSync(flat, dest);
        moved++;
      }
    } catch {
      /* skip a file we can't move; a later scan tombstones it if truly gone */
    }
  }
  return moved;
}

// ---- reads -----------------------------------------------------------------
export async function getNote(db: DB, owner: string, id: string): Promise<NoteJson | null> {
  const row = await db
    .selectFrom('notes')
    .selectAll()
    .where('id', '=', id)
    .where('owner_id', '=', owner)
    .executeTakeFirst();
  if (!row || row.tombstoned) return null;
  let body = '';
  try {
    body = parseNote(fs.readFileSync(abs(owner, row.path), 'utf8')).body;
  } catch {
    /* file vanished out from under us — return empty body */
  }
  return rowToNote(row, body);
}

export interface NoteListItem {
  id: string;
  path: string;
  title: string;
  mtime: string;
  updatedAt: string;
}
export async function listNotes(db: DB, owner: string): Promise<NoteListItem[]> {
  const rows = await db
    .selectFrom('notes')
    .selectAll()
    .where('owner_id', '=', owner)
    .where('tombstoned', '=', 0)
    .orderBy('updated_at', 'desc')
    .execute();
  return rows.map((r) => ({
    id: r.id,
    path: r.path,
    title: r.title,
    mtime: r.mtime,
    updatedAt: r.updated_at,
  }));
}

export interface NoteSearchHit {
  id: string;
  title: string;
  snippet: string;
}
// Every live note's title + body straight from the FTS index — no per-file disk reads.
// The unified query uses this to evaluate predicates in memory (the body is already
// duplicated in notes_fts), so only the notes that actually MATCH get read from disk to
// build the full entity. (Evaluation sees the indexed body; a not-yet-synced external
// edit reconciles on the next sync, same as the rest of the index.)
export async function notesForQuery(
  db: DB,
  owner: string,
): Promise<{ id: string; title: string; body: string }[]> {
  const res = await sql<{ id: string; title: string; body: string }>`
    SELECT note_id AS id, title, body FROM notes_fts WHERE owner_id = ${owner}`.execute(db);
  return res.rows;
}

export async function searchNotes(db: DB, owner: string, q: string): Promise<NoteSearchHit[]> {
  const match = ftsQuery(q);
  if (!match) return [];
  const res = await sql<{ id: string; title: string; snippet: string }>`
    SELECT note_id AS id, title,
           snippet(notes_fts, 3, '[', ']', '…', 12) AS snippet
    FROM notes_fts
    WHERE owner_id = ${owner} AND notes_fts MATCH ${match}
    LIMIT 50`.execute(db);
  return res.rows;
}

// vault.ts — the notes vault. Note *content* lives as raw .md files here; the DB
// only shadows them. App-managed: dirs created on boot if missing. Overridable via
// VAULT_DIR (read lazily so tests can point at a temp dir before the first scan).
//
// Multi-tenant: each owner gets their OWN subdir (vault/<owner_id>/). All paths must
// go through abs(owner, …), which also asserts the resolved path stays inside that
// owner's root — defense-in-depth against a `..`/traversal path slipping through.

import fs from 'node:fs';
import path from 'node:path';
import { fileURLToPath } from 'node:url';

const __dirname = path.dirname(fileURLToPath(import.meta.url));

// the shared base dir holding every owner's vault subdir
export function vaultBase(): string {
  const dir = process.env.VAULT_DIR || path.join(__dirname, '..', 'data', 'vault');
  fs.mkdirSync(dir, { recursive: true });
  return dir;
}

// one owner's vault root
export function vaultRoot(owner: string): string {
  const dir = path.join(vaultBase(), owner);
  fs.mkdirSync(dir, { recursive: true });
  return dir;
}

// absolute path for an owner-relative note path, asserted to stay within the owner's root
export function abs(owner: string, relPath: string): string {
  const root = vaultRoot(owner);
  const p = path.resolve(root, relPath);
  if (p !== root && !p.startsWith(root + path.sep)) {
    throw new Error(`vault path escapes its root: ${relPath}`);
  }
  return p;
}

// markdown.ts — hand-rolled (zero-dep) note parsing for the vault scanner (D2 §4).
// Notes are ordinary markdown with a YAML-subset frontmatter block carrying a
// machine-managed `id:`. The note's TITLE is its filename (Obsidian model), not a
// frontmatter key — so the only managed metadata is the id; every other frontmatter
// key the user wrote is preserved verbatim. We parse the id, the rest of the
// frontmatter, the body, and the [[wikilinks]] the scanner materializes into links.

export interface ParsedNote {
  id: string | null;
  frontmatter: Record<string, string>; // every key except the managed `id`, preserved
  body: string;
}

const FRONTMATTER = /^---\n([\s\S]*?)\n---\n?/;

function unquote(v: string): string {
  if ((v.startsWith('"') && v.endsWith('"')) || (v.startsWith("'") && v.endsWith("'"))) {
    return v.slice(1, -1);
  }
  return v;
}

export function parseNote(raw: string): ParsedNote {
  let body = raw;
  const fm: Record<string, string> = {};
  const m = raw.match(FRONTMATTER);
  if (m) {
    body = raw.slice(m[0].length).replace(/^\n/, ''); // drop the one separator blank line
    for (const line of m[1].split('\n')) {
      const i = line.indexOf(':');
      if (i === -1) continue;
      const key = line.slice(0, i).trim();
      if (key) fm[key] = unquote(line.slice(i + 1).trim());
    }
  }
  const id = fm.id || null;
  const frontmatter: Record<string, string> = {};
  for (const [k, v] of Object.entries(fm)) if (k !== 'id') frontmatter[k] = v; // keep all but id
  return { id, frontmatter, body };
}

// quote a frontmatter scalar only when it could be misread (colon, leading quote/#)
function fmScalar(v: string): string {
  return /[:#"']|^\s|\s$/.test(v) ? `"${v.replace(/"/g, '\\"')}"` : v;
}

// Build a full note file (used for app-created/edited notes, where we own the file).
// Title is the filename, so the frontmatter is just the managed id + any extra keys.
export function serializeNote(opts: {
  id: string;
  body: string;
  frontmatter?: Record<string, string>;
}): string {
  const lines = ['---', `id: ${opts.id}`];
  for (const [k, v] of Object.entries(opts.frontmatter ?? {})) lines.push(`${k}: ${fmScalar(v)}`);
  lines.push('---', '');
  return `${lines.join('\n')}\n${opts.body.replace(/^\n+/, '')}`;
}

// Surgically inject a machine id into an externally-authored file (preserves the
// rest of the frontmatter/body byte-for-byte) — the gentle "writeback" on scan.
export function injectFrontmatterId(raw: string, id: string): string {
  if (FRONTMATTER.test(raw)) return raw.replace(/^---\n/, `---\nid: ${id}\n`);
  return `---\nid: ${id}\n---\n\n${raw}`;
}

export interface ExtractedLinks {
  tasks: string[];
  events: string[];
  notes: string[]; // note-name targets (resolved to ids during reconcile)
}

export function extractLinks(body: string): ExtractedLinks {
  // Construct locally so the stateful `/g` `lastIndex` can never leak between calls.
  const typed = /\[\[(task|event):([\w-]+)(?:\|[^\]\n]*)?\]\]/g; // optional |display alias
  const wiki = /\[\[([^\]]+)\]\]/g;
  const tasks = new Set<string>();
  const events = new Set<string>();
  const notes = new Set<string>();
  for (let m = typed.exec(body); m; m = typed.exec(body)) {
    (m[1] === 'task' ? tasks : events).add(m[2]);
  }
  for (let m = wiki.exec(body); m; m = wiki.exec(body)) {
    const inner = m[1].trim();
    if (/^(task|event):/.test(inner)) continue; // handled above as a typed link
    const name = inner.split('|')[0].split('#')[0].trim(); // strip [[Name|alias]] / [[Name#heading]]
    if (name) notes.add(name);
  }
  return { tasks: [...tasks], events: [...events], notes: [...notes] };
}

// routes/projects.ts — project CRUD with If-Match concurrency + archive cascade.

import type { FastifyInstance } from 'fastify';
import { accessLevel, denyStatus } from '../authz.js';
import { ProjectCreateSchema, ProjectUpdateSchema } from '../schemas.js';
import { PreconditionFailed, etag } from '../services/concurrency.js';
import { archiveProject, createProject, getProject, updateProject } from '../services/projects.js';
import { denyAccess, ifMatchOf } from './_access.js';

export default async function projectRoutes(app: FastifyInstance): Promise<void> {
  app.post(
    '/api/projects',
    { preHandler: app.requireWrite, schema: { body: ProjectCreateSchema } },
    async (request, reply) => {
      const body = request.body as { parentId?: string | null };
      if (body.parentId) {
        const status = denyStatus(
          await accessLevel(app.db, request.user!, 'project', body.parentId),
          'write',
        );
        if (status)
          return reply.code(status).send({ error: status === 404 ? 'not found' : 'forbidden' });
      }
      const project = await createProject(
        app.db,
        request.user!.id,
        request.body as Parameters<typeof createProject>[2],
      );
      return reply.code(201).header('etag', etag(project.updatedAt)).send(project);
    },
  );

  app.get('/api/projects/:id', { preHandler: app.authenticate }, async (request, reply) => {
    const { id } = request.params as { id: string };
    if (await denyAccess(app, request, reply, 'project', id, 'read')) return;
    const project = await getProject(app.db, id);
    if (!project) return reply.code(404).send({ error: 'not found' });
    return reply.header('etag', etag(project.updatedAt)).send(project);
  });

  app.put(
    '/api/projects/:id',
    { preHandler: app.requireWrite, schema: { body: ProjectUpdateSchema } },
    async (request, reply) => {
      const { id } = request.params as { id: string };
      if (await denyAccess(app, request, reply, 'project', id, 'write')) return;
      try {
        const project = await updateProject(
          app.db,
          id,
          request.body as Parameters<typeof updateProject>[2],
          ifMatchOf(request),
        );
        if (!project) return reply.code(404).send({ error: 'not found' });
        return reply.header('etag', etag(project.updatedAt)).send(project);
      } catch (err) {
        if (err instanceof PreconditionFailed) {
          return reply.code(412).send({ error: 'stale', current: await getProject(app.db, id) });
        }
        throw err;
      }
    },
  );

  app.delete('/api/projects/:id', { preHandler: app.requireWrite }, async (request, reply) => {
    const { id } = request.params as { id: string };
    if (await denyAccess(app, request, reply, 'project', id, 'write')) return;
    await archiveProject(app.db, id);
    return reply.code(204).send();
  });
}

// services/projects.ts — project CRUD + archive cascade (subprojects + their tasks).

import type { Updateable } from 'kysely';
import type { DB, ProjectsTable } from '../db.js';
import { newId } from '../ids.js';
import { rowToProject } from '../schemas.js';
import { checkIfMatch } from './concurrency.js';
import { collectSubtree } from './tasks.js';

export interface ProjectCreateInput {
  id?: string;
  name: string;
  parentId?: string | null;
  color?: string;
  glyph?: string;
  collapsed?: boolean;
  health?: string[];
  position?: number;
}
export interface ProjectPatch {
  name?: string;
  parentId?: string | null;
  color?: string;
  glyph?: string;
  collapsed?: boolean;
  position?: number;
  health?: string[];
}

export async function getProject(db: DB, id: string) {
  const row = await db.selectFrom('projects').selectAll().where('id', '=', id).executeTakeFirst();
  return row ? rowToProject(row) : null;
}

export async function createProject(db: DB, owner: string, input: ProjectCreateInput) {
  const id = input.id ?? newId();
  const now = new Date().toISOString();
  const m = await db
    .selectFrom('projects')
    .select((eb) => eb.fn.max('position').as('m'))
    .where('owner_id', '=', owner)
    .executeTakeFirst();
  await db
    .insertInto('projects')
    .values({
      id,
      owner_id: owner,
      parent_id: input.parentId ?? null,
      name: input.name,
      color: input.color ?? '#ffb000',
      glyph: input.glyph ?? '●',
      collapsed: input.collapsed ? 1 : 0,
      position: input.position ?? Number(m?.m ?? 0) + 1,
      archived: 0,
      health: JSON.stringify(input.health ?? []),
      created_at: now,
      updated_at: now,
    })
    .execute();
  return (await getProject(db, id))!;
}

export async function updateProject(db: DB, id: string, patch: ProjectPatch, ifMatch?: string) {
  return db.transaction().execute(async (trx) => {
    const row = await trx
      .selectFrom('projects')
      .selectAll()
      .where('id', '=', id)
      .executeTakeFirst();
    if (!row) return null;
    checkIfMatch(ifMatch, row.updated_at);
    const set: Updateable<ProjectsTable> = { updated_at: new Date().toISOString() };
    if (patch.name !== undefined) set.name = patch.name;
    if (patch.parentId !== undefined) set.parent_id = patch.parentId;
    if (patch.color !== undefined) set.color = patch.color;
    if (patch.glyph !== undefined) set.glyph = patch.glyph;
    if (patch.collapsed !== undefined) set.collapsed = patch.collapsed ? 1 : 0;
    if (patch.position !== undefined) set.position = patch.position;
    if (patch.health !== undefined) set.health = JSON.stringify(patch.health);
    await trx.updateTable('projects').set(set).where('id', '=', id).execute();
    const fresh = await trx
      .selectFrom('projects')
      .selectAll()
      .where('id', '=', id)
      .executeTakeFirst();
    return rowToProject(fresh!);
  });
}

// Soft-delete a project, its subproject subtree, and all of their tasks.
export async function archiveProject(db: DB, id: string): Promise<void> {
  const root = await db
    .selectFrom('projects')
    .select('owner_id')
    .where('id', '=', id)
    .executeTakeFirst();
  if (!root) return;
  const all = await db
    .selectFrom('projects')
    .select(['id', 'parent_id'])
    .where('owner_id', '=', root.owner_id)
    .execute();
  const projIds = collectSubtree(id, all);
  const now = new Date().toISOString();
  await db
    .updateTable('projects')
    .set({ archived: 1, updated_at: now })
    .where('id', 'in', projIds)
    .execute();
  await db
    .updateTable('tasks')
    .set({ archived: 1, updated_at: now })
    .where('owner_id', '=', root.owner_id)
    .where('project_id', 'in', projIds)
    .execute();
}

// services/tasks.ts — task CRUD + archive cascade. Operates by task id; the route
// is the access gate (accessLevel/denyStatus). complete(spawn)/assign live in
// services/recurrence.ts and the assign route.

import type { Kysely, Updateable } from 'kysely';
import type { DB, Database_, TasksTable } from '../db.js';
import { newId } from '../ids.js';
import { type TaskJson, rowToTask } from '../schemas.js';
import { checkIfMatch } from './concurrency.js';

type Trx = Kysely<Database_>;

export interface TaskCreateInput {
  id?: string;
  title: string;
  projectId?: string | null;
  parentId?: string | null;
  done?: boolean;
  due?: string | null;
  reminder?: string | null;
  recurrence?: string | null;
  notes?: string;
  priority?: number;
  size?: number;
  labels?: string[];
  assigneeId?: string | null;
  position?: number;
}
export interface TaskPatch {
  title?: string;
  projectId?: string | null;
  parentId?: string | null;
  done?: boolean;
  due?: string | null;
  reminder?: string | null;
  recurrence?: string | null;
  notes?: string;
  priority?: number;
  size?: number;
  labels?: string[];
  assigneeId?: string | null;
  position?: number;
}

// Replace a task's labels with the subset that actually belongs to `owner`.
async function setTaskLabels(
  trx: Trx,
  owner: string,
  taskId: string,
  labels: string[],
): Promise<void> {
  await trx.deleteFrom('task_labels').where('task_id', '=', taskId).execute();
  if (!labels.length) return;
  const owned = await trx
    .selectFrom('labels')
    .select('id')
    .where('owner_id', '=', owner)
    .where('id', 'in', labels)
    .execute();
  if (owned.length) {
    await trx
      .insertInto('task_labels')
      .values(owned.map((o) => ({ task_id: taskId, label_id: o.id })))
      .onConflict((oc) => oc.doNothing())
      .execute();
  }
}

export async function loadTask(db: DB | Trx, id: string): Promise<TaskJson | null> {
  const row = await db.selectFrom('tasks').selectAll().where('id', '=', id).executeTakeFirst();
  if (!row) return null;
  const labels = (
    await db
      .selectFrom('task_labels')
      .select('label_id')
      .where('task_id', '=', id)
      .orderBy('label_id')
      .execute()
  ).map((r) => r.label_id);
  return rowToTask(row, labels);
}

export const getTask = (db: DB, id: string): Promise<TaskJson | null> => loadTask(db, id);

export async function createTask(db: DB, owner: string, input: TaskCreateInput): Promise<TaskJson> {
  const id = input.id ?? newId();
  const now = new Date().toISOString();
  const done = input.done ? 1 : 0;
  await db.transaction().execute(async (trx) => {
    const position =
      input.position ??
      Number(
        (
          await trx
            .selectFrom('tasks')
            .select((eb) => eb.fn.max('position').as('m'))
            .where('owner_id', '=', owner)
            .executeTakeFirst()
        )?.m ?? 0,
      ) + 1;
    await trx
      .insertInto('tasks')
      .values({
        id,
        owner_id: owner,
        creator_id: owner,
        assignee_id: input.assigneeId ?? null,
        project_id: input.projectId ?? null,
        parent_id: input.parentId ?? null,
        title: input.title,
        done,
        due: input.due ?? null,
        reminder: input.reminder ?? null,
        recurrence: input.recurrence ?? null,
        notes: input.notes ?? '',
        priority: input.priority ?? 0,
        size: input.size ?? 0,
        position,
        archived: 0,
        created_at: now,
        completed_at: done ? now : null,
        updated_at: now,
      })
      .execute();
    if (input.labels?.length) await setTaskLabels(trx, owner, id, input.labels);
  });
  return (await loadTask(db, id))!;
}

// Throws PreconditionFailed on a stale If-Match. Returns null if the task is gone.
export async function updateTask(
  db: DB,
  id: string,
  patch: TaskPatch,
  ifMatch?: string,
): Promise<TaskJson | null> {
  return db.transaction().execute(async (trx) => {
    const row = await trx.selectFrom('tasks').selectAll().where('id', '=', id).executeTakeFirst();
    if (!row) return null;
    checkIfMatch(ifMatch, row.updated_at);

    const now = new Date().toISOString();
    const set: Updateable<TasksTable> = { updated_at: now };
    if (patch.title !== undefined) set.title = patch.title;
    if (patch.projectId !== undefined) set.project_id = patch.projectId;
    if (patch.parentId !== undefined) set.parent_id = patch.parentId;
    if (patch.done !== undefined) {
      set.done = patch.done ? 1 : 0;
      set.completed_at = patch.done ? (row.completed_at ?? now) : null;
    }
    if (patch.due !== undefined) set.due = patch.due;
    if (patch.reminder !== undefined) set.reminder = patch.reminder;
    if (patch.recurrence !== undefined) set.recurrence = patch.recurrence;
    if (patch.notes !== undefined) set.notes = patch.notes;
    if (patch.priority !== undefined) set.priority = patch.priority;
    if (patch.size !== undefined) set.size = patch.size;
    if (patch.assigneeId !== undefined) set.assignee_id = patch.assigneeId;
    if (patch.position !== undefined) set.position = patch.position;

    await trx.updateTable('tasks').set(set).where('id', '=', id).execute();
    if (patch.labels !== undefined) await setTaskLabels(trx, row.owner_id, id, patch.labels);
    return loadTask(trx, id);
  });
}

// Set/clear the assignee. Returns 'badAssignee' if the user doesn't exist,
// null if the task is gone, else the updated task.
export async function assignTask(
  db: DB,
  id: string,
  assigneeId: string | null,
): Promise<TaskJson | null | 'badAssignee'> {
  if (assigneeId) {
    const u = await db
      .selectFrom('users')
      .select('id')
      .where('id', '=', assigneeId)
      .executeTakeFirst();
    if (!u) return 'badAssignee';
  }
  const row = await db.selectFrom('tasks').select('id').where('id', '=', id).executeTakeFirst();
  if (!row) return null;
  await db
    .updateTable('tasks')
    .set({ assignee_id: assigneeId, updated_at: new Date().toISOString() })
    .where('id', '=', id)
    .execute();
  return loadTask(db, id);
}

// Soft-delete a task and its whole subtask subtree (archived=1).
export async function archiveTask(db: DB, id: string): Promise<void> {
  const root = await db
    .selectFrom('tasks')
    .select('owner_id')
    .where('id', '=', id)
    .executeTakeFirst();
  if (!root) return;
  const all = await db
    .selectFrom('tasks')
    .select(['id', 'parent_id'])
    .where('owner_id', '=', root.owner_id)
    .execute();
  const ids = collectSubtree(id, all);
  await db
    .updateTable('tasks')
    .set({ archived: 1, updated_at: new Date().toISOString() })
    .where('id', 'in', ids)
    .execute();
}

export function collectSubtree(
  rootId: string,
  rows: { id: string; parent_id: string | null }[],
): string[] {
  const childMap = new Map<string, string[]>();
  for (const r of rows) {
    if (r.parent_id) {
      const a = childMap.get(r.parent_id) ?? [];
      a.push(r.id);
      childMap.set(r.parent_id, a);
    }
  }
  const out: string[] = [];
  const stack = [rootId];
  while (stack.length) {
    const x = stack.pop()!;
    out.push(x);
    for (const c of childMap.get(x) ?? []) stack.push(c);
  }
  return out;
}

// routes/query.ts — POST /api/query: the unified entity query. `type:task,event,note`
// selects which entity types to return (default: task); every other predicate is run by
// the parity-locked `Q` engine across all selected types (see services/unifiedQuery.ts).
// Read scope is sufficient.

import { Type } from '@fastify/type-provider-typebox';
import type { FastifyInstance } from 'fastify';
import { QueryRequestSchema, QueryResponseSchema } from '../schemas.js';
import { UnknownTypeError, runUnifiedQuery } from '../services/unifiedQuery.js';

export default async function queryRoutes(app: FastifyInstance): Promise<void> {
  app.post(
    '/api/query',
    {
      preHandler: app.authenticate,
      schema: {
        body: QueryRequestSchema,
        response: {
          200: QueryResponseSchema,
          400: Type.Object({ error: Type.String() }), // unknown type: token
        },
      },
    },
    async (request, reply) => {
      const { query, limit, offset } = request.body as {
        query: string;
        limit?: number;
        offset?: number;
      };
      const user = request.user!;
      let all: Awaited<ReturnType<typeof runUnifiedQuery>>;
      try {
        all = await runUnifiedQuery(app.db, user.id, user.week_start, query);
      } catch (err) {
        if (err instanceof UnknownTypeError) return reply.code(400).send({ error: err.message });
        throw err;
      }
      const total = all.length;
      const start = offset ?? 0;
      const items = limit != null ? all.slice(start, start + limit) : all.slice(start);
      return { items, total };
    },
  );
}

// services/unifiedQuery.ts — the unified entity query (D2 2d slice 2). `POST /api/query`
// gains a `type:task,event,note` predicate that returns MIXED entities. We do NOT touch
// the parity-locked `Q` engine: instead we strip `type:` ourselves, then reuse `Q.evaluate`
// for every type by mapping events/notes onto Q's loose `Task` shape (title/notes/due/…).
// So all three honor the SAME free-text + date predicates, via the same engine, with zero
// parity risk. Tasks that don't apply (project:/label:) naturally exclude events/notes.
//
// Note: events are matched on their series start date (no occurrence expansion here — the
// calendar grid still uses GET /api/events for that), and we scan all events/notes in JS;
// pushing predicates down to SQL/FTS is a later optimization.

import type { DB } from '../db.js';
import { type Ctx, Q, type Task } from '../query.js';
import { Rec } from '../rec.js';
import { type EventJson, type TaskJson, rowToEvent } from '../schemas.js';
import { readBootstrap } from './bootstrap.js';
import { getNote, notesForQuery } from './notes.js';

export type EntityType = 'task' | 'event' | 'note';
const ENTITY_TYPES: readonly EntityType[] = ['task', 'event', 'note'];

// Thrown when a `type:`/`-type:` token isn't one of ENTITY_TYPES. The route turns
// this into a 400 with the message so the user sees their typo (e.g. `type:even`)
// rather than silently getting nothing — we never guess what they meant.
export class UnknownTypeError extends Error {
  constructor(public readonly tokens: string[]) {
    super(
      `unknown type ${tokens.length > 1 ? 'tokens' : 'token'}: ${tokens.join(', ')} — valid types are ${ENTITY_TYPES.join(', ')}`,
    );
    this.name = 'UnknownTypeError';
  }
}

export interface QueryItem {
  type: EntityType;
  [k: string]: unknown;
}

// Map an event occurrence onto Q's Task shape: free-text covers title+notes+location; date
// predicates (due:/status:) read the occurrence's date; recurring:true sees `recurrence`.
// A past occurrence reads as DONE (so status:done matches and status:overdue does not) — an
// event that already happened is complete, not overdue like a missed task.
function eventAsTask(e: EventJson, occDate: string, todayYMD: string): Task {
  return {
    id: e.id,
    title: e.title,
    notes: `${e.notes} ${e.location ?? ''}`.trim(),
    due: occDate,
    reminder: e.reminder,
    recurrence: e.recurrence,
    done: occDate < todayYMD,
    labels: [],
  };
}
// Map a note: free-text covers title (filename) + body. No due/labels yet (labels land later).
function noteAsTask(n: { id: string; title: string; body: string }): Task {
  return { id: n.id, title: n.title, notes: n.body, due: null, done: false, labels: [] };
}

export async function runUnifiedQuery(
  db: DB,
  owner: string,
  weekStart: number,
  queryStr: string,
): Promise<QueryItem[]> {
  const parsed = Q.parse(queryStr);
  // Collect type selectors. `type:` includes, `-type:` excludes; every token must be a
  // known entity type (a typo errors out — we never fall back to a default that hides it).
  const positives = new Set<EntityType>();
  const negatives = new Set<EntityType>();
  const unknown: string[] = [];
  for (const t of parsed.terms.filter((t) => t.field === 'type')) {
    for (const tok of t.value.split(',').map((s) => s.trim())) {
      if (!tok) continue;
      if (!(ENTITY_TYPES as readonly string[]).includes(tok)) unknown.push(tok);
      else (t.neg ? negatives : positives).add(tok as EntityType);
    }
  }
  if (unknown.length) throw new UnknownTypeError([...new Set(unknown)]);
  // base set: explicit includes if any; else everything (when only excluding); else the
  // task default. Then drop excluded types.
  const base: EntityType[] =
    positives.size > 0 ? [...positives] : negatives.size > 0 ? [...ENTITY_TYPES] : ['task'];
  const types = base.filter((t) => !negatives.has(t));
  // everything except the type selector is the actual predicate set, shared across types
  const pq = { terms: parsed.terms.filter((t) => t.field !== 'type'), ok: true };

  const { tasks, projects, labels } = await readBootstrap(db, owner);
  const ctx = { tasks, projects, labels, weekStart } as unknown as Ctx;
  const todayD = Rec.startOfDay(new Date());
  const todayYMD = Rec.ymd(todayD);
  const out: QueryItem[] = [];

  if (types.includes('task')) {
    for (const t of Q.run(pq, ctx) as unknown as TaskJson[]) out.push({ type: 'task', ...t });
  }
  if (types.includes('event')) {
    const rows = await db
      .selectFrom('events')
      .selectAll()
      .where('owner_id', '=', owner)
      .where('archived', '=', 0)
      .execute();
    // Recurring events are matched against their OCCURRENCES (not just the series start),
    // but only when the query carries a date predicate (`due:`) — otherwise the start-date
    // test is enough and we avoid pointless expansion. Each series yields at most ONE row,
    // dated to the soonest relevant occurrence (next upcoming, else most recent past), with
    // `count` = how many occurrences match inside the window. Open-ended date predicates
    // (e.g. due:set) are bounded to today ± 1 year.
    const hasDuePred = pq.terms.some((t) => t.field === 'due');
    const winFrom = Rec.addDays(todayD, -365);
    const winTo = Rec.addDays(todayD, 365);
    for (const row of rows) {
      const ev = rowToEvent(row);
      const start = ev.startAt.slice(0, 10);
      const rule = ev.recurrence ? Rec.parse(ev.recurrence) : null;

      if (!hasDuePred || !rule || rule.type === 'invalid') {
        // non-recurring, or nothing date-sensitive to expand → test the start date once
        if (Q.evaluate(eventAsTask(ev, start, todayYMD), pq, ctx))
          out.push({ type: 'event', date: start, count: 1, ...ev });
        continue;
      }
      // recurring + a due: predicate → walk the window, count matches, pick the display date
      const anchor = Rec.parseYMD(start) as Date;
      let count = 0;
      let nextFuture: string | null = null;
      let lastPast: string | null = null;
      for (let d = new Date(winFrom); d <= winTo; d = Rec.addDays(d, 1)) {
        const dymd = Rec.ymd(d);
        if (dymd < start) continue; // before the series began
        if (!Rec.matches(d, rule, anchor)) continue;
        if (!Q.evaluate(eventAsTask(ev, dymd, todayYMD), pq, ctx)) continue;
        count++;
        if (dymd >= todayYMD) {
          if (nextFuture === null) nextFuture = dymd; // soonest upcoming match
        } else {
          lastPast = dymd; // most recent past match (fallback when nothing's upcoming)
        }
      }
      if (count > 0) out.push({ type: 'event', date: nextFuture ?? lastPast, count, ...ev });
    }
  }
  if (types.includes('note')) {
    // Evaluate against the FTS-indexed title+body (in memory); only hit disk for matches.
    for (const row of await notesForQuery(db, owner)) {
      if (!Q.evaluate(noteAsTask(row), pq, ctx)) continue;
      const n = await getNote(db, owner, row.id); // full entity (path/frontmatter/timestamps)
      if (n) out.push({ type: 'note', ...n });
    }
  }
  return out;
}

// query.ts — TypeScript port of frontend/js/query.js. Behavior intended identical
// (parity-tested against the Phase 0 goldens); the only changes are window.Q ->
// exports, the bare global `Rec` -> an import, and light types. Grammar unchanged
// — see the original header.

import { Rec } from './rec.js';

export interface Task {
  id?: string;
  title?: string;
  notes?: string;
  projectId?: string;
  parentId?: string | null;
  labels?: string[];
  done?: boolean;
  due?: string | null;
  reminder?: string | null;
  recurrence?: string | null;
  priority?: number;
  size?: number;
  [k: string]: unknown;
}
export interface Project {
  id: string;
  name: string;
  [k: string]: unknown;
}
export interface Label {
  id: string;
  name: string;
  [k: string]: unknown;
}
export interface Ctx {
  tasks?: Task[];
  projects?: Project[];
  labels?: Label[];
  weekStart?: number;
}
export interface Term {
  field: string;
  value: string;
  neg: boolean;
}
export interface ParsedQuery {
  terms: Term[];
  ok: boolean;
}

const today = () => Rec.startOfDay(new Date());

// tokenize respecting quotes
function tokenize(str: string): string[] {
  const out: string[] = [];
  const re = /"([^"]*)"|(\S+)/g;
  let m: RegExpExecArray | null;
  while ((m = re.exec(str))) out.push(m[1] !== undefined ? `"${m[1]}"` : m[2]);
  return out;
}

function parse(str: string | null | undefined): ParsedQuery {
  const terms: Term[] = [];
  if (!str || !str.trim()) return { terms, ok: true };
  for (let tok of tokenize(str)) {
    let neg = false;
    if (tok.startsWith('-') && tok.length > 1 && tok.indexOf(':') > 0) {
      neg = true;
      tok = tok.slice(1);
    }
    const qi = tok.indexOf(':');
    if (qi > 0 && !tok.startsWith('"')) {
      const field = tok.slice(0, qi).toLowerCase();
      const value = tok.slice(qi + 1).toLowerCase();
      terms.push({ field, value, neg });
    } else {
      terms.push({ field: 'text', value: tok.replace(/^"|"$/g, '').toLowerCase(), neg });
    }
  }
  return { terms, ok: true };
}

// resolve a project token (id or slug of name) -> set of matching project ids only
// (exact: subprojects are NOT included, so a parent's view/count shows just its own tasks)
function resolveProjects(value: string, ctx: Ctx): Set<string> {
  const projects = ctx.projects || [];
  const match = projects.filter(
    (p) => p.id === value || slug(p.name) === slug(value) || slug(p.name).includes(slug(value)),
  );
  return new Set(match.map((p) => p.id));
}
function slug(s: string | null | undefined): string {
  return String(s || '')
    .toLowerCase()
    .replace(/[^a-z0-9]+/g, '');
}

function dueDelta(task: Task): number | null {
  // days from today to due (negative = overdue). null if no due.
  if (!task.due) return null;
  return Rec.daysBetween(today(), Rec.parseYMD(task.due) as Date);
}
function remDelta(task: Task): number | null {
  if (!task.reminder) return null;
  // reminder may be a 'YYYY-MM-DDTHH:MM' timestamp; query filters are day-grained.
  return Rec.daysBetween(today(), Rec.parseYMD(task.reminder.slice(0, 10)) as Date);
}

function cmpDate(delta: number | null, op: string): boolean {
  // op like "<7d", "<=3d", ">0d", "=0d"
  const mm = op.match(/^(<=|>=|<|>|=)(-?\d+)d$/);
  if (!mm || delta === null) return false;
  const o = mm[1];
  const n = +mm[2];
  switch (o) {
    case '<':
      return delta < n;
    case '>':
      return delta > n;
    case '<=':
      return delta <= n;
    case '>=':
      return delta >= n;
    case '=':
      return delta === n;
  }
  return false;
}

// ---- weekday window (due:su, due:mwf, …) ----------------------------------
// letter -> JS getDay() (0=Sun … 6=Sat)
const DOW: Record<string, number> = { u: 0, m: 1, t: 2, w: 3, r: 4, f: 5, s: 6 };
function weekdaySet(v: string): Set<number> {
  const s = new Set<number>();
  for (const c of String(v || '')) {
    if (c in DOW) s.add(DOW[c]);
  }
  return s;
}
// The active cycle's dates for the selected weekdays. weekStart: 0=Sun..6=Sat (default Mon).
// Window = this week's selected days, rolling to next week once we're past the last one.
function dueWindow(daySet: Set<number>, weekStart?: number): string[] {
  weekStart = weekStart == null ? 1 : weekStart;
  if (!daySet.size) return [];
  const now = today(); // Rec.startOfDay(new Date())
  const back = (now.getDay() - weekStart + 7) % 7; // days since the week start
  const start = Rec.addDays(now, -back);
  let dates = [...daySet].map((d) => Rec.addDays(start, (d - (weekStart as number) + 7) % 7));
  const last = dates.reduce((a, b) => (a > b ? a : b));
  if (now > last) dates = dates.map((d) => Rec.addDays(d, 7)); // past the window -> next week
  return dates.map(Rec.ymd);
}

function evalTerm(task: Task, t: Term, ctx: Ctx): boolean {
  const labelsOf = task.labels || [];
  let res = false;
  switch (t.field) {
    case 'text':
      res =
        (task.title || '').toLowerCase().includes(t.value) ||
        (task.notes || '').toLowerCase().includes(t.value);
      break;
    case 'project': {
      const ids = resolveProjects(t.value, ctx);
      res = ids.has(task.projectId as string);
      break;
    }
    case 'label': {
      const wants = t.value.split(',').map(slug);
      res = labelsOf.some((lid) => {
        const lab = (ctx.labels || []).find((l) => l.id === lid);
        return lab && wants.includes(slug(lab.name));
      });
      break;
    }
    case 'status': {
      const d = dueDelta(task);
      if (t.value === 'done') res = !!task.done;
      else if (t.value === 'open') res = !task.done;
      else if (t.value === 'overdue') res = !task.done && d !== null && d < 0;
      else if (t.value === 'today') res = !task.done && d === 0;
      break;
    }
    case 'due': {
      const d = dueDelta(task);
      if (t.value === 'none') res = d === null;
      else if (t.value === 'set') res = d !== null;
      else if (t.value === 'today') res = d === 0;
      else if (t.value === 'tomorrow') res = d === 1;
      else if (t.value === 'overdue') res = d !== null && d < 0;
      else if (t.value === 'week') res = d !== null && d >= 0 && d <= 7;
      else if (t.value === 'month') res = d !== null && d >= 0 && d <= 31;
      else if (/^[mtwrfsu]+$/.test(t.value))
        res =
          !!task.due &&
          dueWindow(weekdaySet(t.value), ctx.weekStart).includes(task.due.slice(0, 10));
      else res = cmpDate(d, t.value);
      break;
    }
    case 'reminder': {
      const d = remDelta(task);
      if (t.value === 'none') res = d === null;
      else if (t.value === 'set') res = d !== null;
      else if (t.value === 'today') res = d === 0;
      else if (t.value === 'overdue') res = d !== null && d < 0;
      else res = cmpDate(d, t.value);
      break;
    }
    case 'recurring':
      res = t.value === 'true' ? !!task.recurrence : !task.recurrence;
      break;
    case 'is':
      if (t.value === 'subtask') res = !!task.parentId;
      else if (t.value === 'task') res = !task.parentId;
      else if (t.value === 'recurring') res = !!task.recurrence;
      else if (t.value === 'done') res = !!task.done;
      else if (t.value === 'open') res = !task.done;
      break;
    case 'has':
      if (t.value === 'subtasks') res = (ctx.tasks || []).some((x) => x.parentId === task.id);
      else if (t.value === 'label') res = labelsOf.length > 0;
      else if (t.value === 'no-labels') res = labelsOf.length === 0;
      else if (t.value === 'due') res = !!task.due;
      break;
    default:
      // unknown field -> treat as text match on "field:value"
      res = (task.title || '').toLowerCase().includes(`${t.field}:${t.value}`);
  }
  return t.neg ? !res : res;
}

function evaluate(task: Task, query: string | ParsedQuery, ctx: Ctx): boolean {
  const q = typeof query === 'string' ? parse(query) : query;
  if (!q.terms.length) return true;
  return q.terms.every((t) => evalTerm(task, t, ctx));
}

// run query over the task list -> matching tasks (flat)
function run(query: string | ParsedQuery, ctx: Ctx): Task[] {
  return (ctx.tasks || []).filter((t) => evaluate(t, query, ctx));
}

// ---- builder helpers: structured <-> string ---------------
// We keep builder state as an array of {field,value,neg}; string is the join.
function termToString(t: Term): string {
  const body =
    t.field === 'text' ? (/\s/.test(t.value) ? `"${t.value}"` : t.value) : `${t.field}:${t.value}`;
  return (t.neg ? '-' : '') + body;
}
function build(terms: Term[]): string {
  return terms.map(termToString).join(' ');
}

export const Q = { parse, evaluate, run, build, termToString, tokenize, slug, dueDelta };
export default Q;
export { parse, evaluate, run, build, termToString, tokenize, slug, dueDelta };

// routes/savedQueries.ts — saved-query CRUD. No updated_at → unconditional writes.

import type { FastifyInstance } from 'fastify';
import { SavedQueryCreateSchema, SavedQueryUpdateSchema } from '../schemas.js';
import {
  createSavedQuery,
  deleteSavedQuery,
  getSavedQuery,
  updateSavedQuery,
} from '../services/savedQueries.js';
import { denyAccess } from './_access.js';

export default async function savedQueryRoutes(app: FastifyInstance): Promise<void> {
  app.post(
    '/api/saved-queries',
    { preHandler: app.requireWrite, schema: { body: SavedQueryCreateSchema } },
    async (request, reply) => {
      const sv = await createSavedQuery(
        app.db,
        request.user!.id,
        request.body as Parameters<typeof createSavedQuery>[2],
      );
      return reply.code(201).send(sv);
    },
  );

  app.get('/api/saved-queries/:id', { preHandler: app.authenticate }, async (request, reply) => {
    const { id } = request.params as { id: string };
    if (await denyAccess(app, request, reply, 'saved_query', id, 'read')) return;
    return getSavedQuery(app.db, id);
  });

  app.put(
    '/api/saved-queries/:id',
    { preHandler: app.requireWrite, schema: { body: SavedQueryUpdateSchema } },
    async (request, reply) => {
      const { id } = request.params as { id: string };
      if (await denyAccess(app, request, reply, 'saved_query', id, 'write')) return;
      return updateSavedQuery(app.db, id, request.body as Parameters<typeof updateSavedQuery>[2]);
    },
  );

  app.delete('/api/saved-queries/:id', { preHandler: app.requireWrite }, async (request, reply) => {
    const { id } = request.params as { id: string };
    if (await denyAccess(app, request, reply, 'saved_query', id, 'write')) return;
    await deleteSavedQuery(app.db, id);
    return reply.code(204).send();
  });
}

// services/savedQueries.ts — saved-query CRUD (no updated_at → unconditional).

import type { Updateable } from 'kysely';
import type { DB, SavedQueriesTable } from '../db.js';
import { newId } from '../ids.js';
import { rowToSavedQuery } from '../schemas.js';

export interface SavedQueryCreateInput {
  id?: string;
  name: string;
  query: string;
  glyph?: string;
  color?: string | null;
  pinned?: boolean;
  position?: number;
}
export interface SavedQueryPatch {
  name?: string;
  query?: string;
  glyph?: string;
  color?: string | null;
  pinned?: boolean;
  position?: number;
}

export async function getSavedQuery(db: DB, id: string) {
  const row = await db
    .selectFrom('saved_queries')
    .selectAll()
    .where('id', '=', id)
    .executeTakeFirst();
  return row ? rowToSavedQuery(row) : null;
}

export async function createSavedQuery(db: DB, owner: string, input: SavedQueryCreateInput) {
  const id = input.id ?? newId();
  const m = await db
    .selectFrom('saved_queries')
    .select((eb) => eb.fn.max('position').as('m'))
    .where('owner_id', '=', owner)
    .executeTakeFirst();
  await db
    .insertInto('saved_queries')
    .values({
      id,
      owner_id: owner,
      name: input.name,
      glyph: input.glyph ?? '◆',
      query: input.query,
      system: 0,
      color: input.color ?? null,
      position: input.position ?? Number(m?.m ?? 0) + 1,
      pinned: input.pinned ? 1 : 0,
    })
    .execute();
  return (await getSavedQuery(db, id))!;
}

export async function updateSavedQuery(db: DB, id: string, patch: SavedQueryPatch) {
  const set: Updateable<SavedQueriesTable> = {};
  if (patch.name !== undefined) set.name = patch.name;
  if (patch.query !== undefined) set.query = patch.query;
  if (patch.glyph !== undefined) set.glyph = patch.glyph;
  if (patch.color !== undefined) set.color = patch.color;
  if (patch.pinned !== undefined) set.pinned = patch.pinned ? 1 : 0;
  if (patch.position !== undefined) set.position = patch.position;
  if (Object.keys(set).length)
    await db.updateTable('saved_queries').set(set).where('id', '=', id).execute();
  return getSavedQuery(db, id);
}

export async function deleteSavedQuery(db: DB, id: string): Promise<void> {
  await db.deleteFrom('saved_queries').where('id', '=', id).execute();
}

// routes/tasks.ts — task CRUD. Reads need access read; writes need write scope +
// write access. Tasks/projects carry updated_at, so writes honor If-Match (stale
// → 412 with the current entity). Request bodies are TypeBox-validated; responses
// are built by the shared mappers (validated by the bootstrap/query schemas).

import type { FastifyInstance } from 'fastify';
import { accessLevel, denyStatus } from '../authz.js';
import { AssignSchema, TaskCreateSchema, TaskUpdateSchema } from '../schemas.js';
import { PreconditionFailed, etag } from '../services/concurrency.js';
import { completeTask } from '../services/recurrence.js';
import { archiveTask, assignTask, createTask, getTask, updateTask } from '../services/tasks.js';
import { denyAccess, ifMatchOf } from './_access.js';

export default async function taskRoutes(app: FastifyInstance): Promise<void> {
  app.post(
    '/api/tasks',
    { preHandler: app.requireWrite, schema: { body: TaskCreateSchema } },
    async (request, reply) => {
      const body = request.body as { projectId?: string | null };
      if (body.projectId) {
        const status = denyStatus(
          await accessLevel(app.db, request.user!, 'project', body.projectId),
          'write',
        );
        if (status)
          return reply.code(status).send({ error: status === 404 ? 'not found' : 'forbidden' });
      }
      const task = await createTask(
        app.db,
        request.user!.id,
        request.body as Parameters<typeof createTask>[2],
      );
      return reply.code(201).header('etag', etag(task.updatedAt)).send(task);
    },
  );

  app.get('/api/tasks/:id', { preHandler: app.authenticate }, async (request, reply) => {
    const { id } = request.params as { id: string };
    if (await denyAccess(app, request, reply, 'task', id, 'read')) return;
    const task = await getTask(app.db, id);
    if (!task) return reply.code(404).send({ error: 'not found' });
    return reply.header('etag', etag(task.updatedAt)).send(task);
  });

  app.put(
    '/api/tasks/:id',
    { preHandler: app.requireWrite, schema: { body: TaskUpdateSchema } },
    async (request, reply) => {
      const { id } = request.params as { id: string };
      if (await denyAccess(app, request, reply, 'task', id, 'write')) return;
      try {
        const task = await updateTask(
          app.db,
          id,
          request.body as Parameters<typeof updateTask>[2],
          ifMatchOf(request),
        );
        if (!task) return reply.code(404).send({ error: 'not found' });
        return reply.header('etag', etag(task.updatedAt)).send(task);
      } catch (err) {
        if (err instanceof PreconditionFailed) {
          return reply.code(412).send({ error: 'stale', current: await getTask(app.db, id) });
        }
        throw err;
      }
    },
  );

  app.delete('/api/tasks/:id', { preHandler: app.requireWrite }, async (request, reply) => {
    const { id } = request.params as { id: string };
    if (await denyAccess(app, request, reply, 'task', id, 'write')) return;
    await archiveTask(app.db, id);
    return reply.code(204).send();
  });

  // complete: marks done and, if recurring, spawns the next occurrence + a fresh
  // unchecked subtask subtree. Returns { task, created }.
  app.post('/api/tasks/:id/complete', { preHandler: app.requireWrite }, async (request, reply) => {
    const { id } = request.params as { id: string };
    if (await denyAccess(app, request, reply, 'task', id, 'write')) return;
    const result = await completeTask(app.db, id);
    if (!result) return reply.code(404).send({ error: 'not found' });
    return result;
  });

  app.post(
    '/api/tasks/:id/assign',
    { preHandler: app.requireWrite, schema: { body: AssignSchema } },
    async (request, reply) => {
      const { id } = request.params as { id: string };
      if (await denyAccess(app, request, reply, 'task', id, 'write')) return;
      const { assigneeId } = request.body as { assigneeId: string | null };
      const result = await assignTask(app.db, id, assigneeId);
      if (result === 'badAssignee')
        return reply.code(400).send({ error: 'assignee does not exist', field: 'assigneeId' });
      if (!result) return reply.code(404).send({ error: 'not found' });
      return result;
    },
  );
}

// services/recurrence.ts — completing a recurring task spawns the next occurrence
// (a fresh root clone + a fresh, unchecked clone of the whole subtask subtree).
// Faithful to frontend/js/data.js store.toggleDone + cloneSubtree + shiftReminder;
// behavior is characterized by test/goldens/store.spawn.json (validated in JS).

import type { Kysely } from 'kysely';
import type { DB, Database_, TasksTable } from '../db.js';
import { newId } from '../ids.js';
import { Rec } from '../rec.js';
import type { TaskJson } from '../schemas.js';
import { loadTask } from './tasks.js';

type Trx = Kysely<Database_>;

export interface SpawnResult {
  task: TaskJson;
  created: TaskJson[];
}

// reminder 'YYYY-MM-DDTHH:MM' — preserve its time-of-day and day-gap from the due
// date across the recurrence (ported verbatim).
function shiftReminder(reminder: string | null, due: string | null, nextDue: Date): string | null {
  if (!reminder || !due) return null;
  const remDate = reminder.slice(0, 10);
  const time = reminder.length > 10 ? reminder.slice(10) : '';
  const gap = Rec.daysBetween(Rec.parseYMD(due) as Date, Rec.parseYMD(remDate) as Date);
  return Rec.ymd(Rec.addDays(nextDue, gap)) + time;
}

// Insert a fresh clone of `src` (new id, done=0) under `parentId`, copying labels.
async function cloneTask(
  trx: Trx,
  src: TasksTable,
  parentId: string | null,
  due: string | null,
  reminder: string | null,
): Promise<string> {
  const id = newId();
  const now = new Date().toISOString();
  const m = await trx
    .selectFrom('tasks')
    .select((eb) => eb.fn.max('position').as('m'))
    .where('owner_id', '=', src.owner_id)
    .executeTakeFirst();
  await trx
    .insertInto('tasks')
    .values({
      id,
      owner_id: src.owner_id,
      creator_id: src.owner_id,
      assignee_id: src.assignee_id,
      project_id: src.project_id,
      parent_id: parentId,
      title: src.title,
      done: 0,
      due,
      reminder,
      recurrence: src.recurrence,
      notes: src.notes,
      priority: src.priority,
      size: src.size,
      position: Number(m?.m ?? 0) + 1,
      archived: 0,
      created_at: now,
      completed_at: null,
      updated_at: now,
    })
    .execute();
  const labs = await trx
    .selectFrom('task_labels')
    .select('label_id')
    .where('task_id', '=', src.id)
    .execute();
  if (labs.length) {
    await trx
      .insertInto('task_labels')
      .values(labs.map((l) => ({ task_id: id, label_id: l.label_id })))
      .onConflict((oc) => oc.doNothing())
      .execute();
  }
  return id;
}

// Recreate every descendant of origParentId under newParentId, reset to unchecked.
async function cloneSubtree(
  trx: Trx,
  owner: string,
  origParentId: string,
  newParentId: string,
  collected: string[],
): Promise<void> {
  const subs = await trx
    .selectFrom('tasks')
    .selectAll()
    .where('parent_id', '=', origParentId)
    .where('owner_id', '=', owner)
    .orderBy('position')
    .orderBy('id')
    .execute();
  for (const s of subs) {
    const childId = await cloneTask(trx, s, newParentId, s.due, s.reminder);
    collected.push(childId);
    await cloneSubtree(trx, owner, s.id, childId, collected);
  }
}

export async function completeTask(db: DB, id: string): Promise<SpawnResult | null> {
  return db.transaction().execute(async (trx) => {
    const t = await trx.selectFrom('tasks').selectAll().where('id', '=', id).executeTakeFirst();
    if (!t) return null;
    const now = new Date().toISOString();
    await trx
      .updateTable('tasks')
      .set({ done: 1, completed_at: now, updated_at: now })
      .where('id', '=', id)
      .execute();

    const created: string[] = [];
    if (t.recurrence) {
      const nxt = Rec.next(t.recurrence, t.due ?? Rec.ymd(new Date()), t.due ?? undefined);
      if (nxt) {
        const rootId = await cloneTask(
          trx,
          t,
          t.parent_id,
          Rec.ymd(nxt),
          shiftReminder(t.reminder, t.due, nxt),
        );
        created.push(rootId);
        await cloneSubtree(trx, t.owner_id, t.id, rootId, created);
      }
    }

    const task = (await loadTask(trx, id))!;
    const createdTasks: TaskJson[] = [];
    for (const cid of created) createdTasks.push((await loadTask(trx, cid))!);
    return { task, created: createdTasks };
  });
}

// routes/tokens.ts — API token (PAT) management. Create/revoke require write
// scope (a read-only PAT cannot mint or revoke tokens); listing is a read.

import type { FastifyInstance } from 'fastify';
import { createToken, listTokens, revokeToken } from '../tokens.js';

export default async function tokenRoutes(app: FastifyInstance): Promise<void> {
  app.post('/api/auth/tokens', { preHandler: app.requireWrite }, async (request, reply) => {
    const body = (request.body ?? {}) as { name?: unknown; scopes?: unknown };
    const name = String(body.name ?? '').trim();
    if (!name) return reply.code(400).send({ error: 'name is required', field: 'name' });
    const scopes =
      Array.isArray(body.scopes) && body.scopes.length ? body.scopes.map(String) : ['*'];
    const { id, token } = await createToken(app.db, request.user!.id, name, scopes);
    return reply.code(201).send({ id, name, scopes, token }); // token shown once
  });

  app.get('/api/auth/tokens', { preHandler: app.authenticate }, async (request) => {
    return listTokens(app.db, request.user!.id);
  });

  app.delete('/api/auth/tokens/:id', { preHandler: app.requireWrite }, async (request, reply) => {
    const { id } = request.params as { id: string };
    const ok = await revokeToken(app.db, request.user!.id, id);
